INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3565, 100351, 'tt0059773', NULL, 'Sylvia', 'Sylvia', 'movie', 1965, 'https://image.tmdb.org/t/p/w500/hlj82S7ylTRWkblPactEGnyjW8h.jpg', 'https://image.tmdb.org/t/p/original/sUEjmDFk0bjEen3Hpq818lZZz0P.jpg', 'Sylvia West (Carroll Baker) may not be who she says she is. Her fiancé, the very well-to-do Frederick Summers (Peter Lawford), hires an investigator named Alan Maklin (George Maharis) to do some digging, and what he finds out about her life prior to becoming a writer is quite shocking. Will the newfound knowledge ruin the marriage? Gordon Douglas (Young at Heart) directs this drama, which is based on E.V. Cunningham''s book.', NULL, NULL, 0.6587, 6.333, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
