INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3568, 15867, 'tt0077742', NULL, 'Interiors', 'Interiors', 'movie', 1978, 'https://image.tmdb.org/t/p/w500/sTPy6Kfa1FRED1eaZdVex8b2MdB.jpg', 'https://image.tmdb.org/t/p/original/pW5UUdIWYfDWk2BAOR0fspYGb7q.jpg', 'When Eve, an interior designer, is deserted by her husband of many years, Arthur, the emotionally glacial relationships of the three grown-up daughters are laid bare. Twisted by jealousy, insecurity and resentment, Renata, a successful writer; Joey, a woman crippled by indecision; and Flyn, a budding actress; struggle to communicate for the sake of their shattered mother. But when their father unexpectedly falls for another woman, his decision to remarry sets in motion a terrible twist of fate…', NULL, NULL, 0.9326, 6.85, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
