INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3584, 1200320, 'tt29101725', NULL, 'Killing Faith', 'Killing Faith', 'movie', 2025, 'https://image.tmdb.org/t/p/w500/lzqqjVZsQu8NZOeAYZffP5FKnRy.jpg', 'https://image.tmdb.org/t/p/original/dC15RaDX4mmPB0omILrjTKMGy6W.jpg', 'In the summer of 1859, a widowed physician reluctantly agrees to take a recently freed slave and her mysterious Caucasian daughter on a five-day journey through the bloody West to find a distant town''s Faith Healer. The woman believes her daughter is possessed. The doctor believes she simply carries The Sickness. Either way the fact remains that every living thing the girl touches mysteriously dies.', NULL, NULL, 1.9195, 5.684, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
