INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3669, 32567, 'tt0264578', NULL, 'The Endurance', 'The Endurance - Shackleton''s Legendary Antarctic Expedition', 'movie', 2000, 'https://image.tmdb.org/t/p/w500/7zWvRlfnDTbmcGw8F28PEx7KX2k.jpg', 'https://image.tmdb.org/t/p/original/bbCygAkvqSc0hWdn1Iiv574J0H7.jpg', 'Documentary on the Shackleton Antartic expedition. A retelling of Sir Ernest Shackleton''s ill-fated expedition to Antarctica in and the crew of his vessel ''The Endurance'', which was trapped in the ice floes and frigid open ocean of the Antarctic in 1914. Shackleton decided, with many of his crew injured and weak from exposure and starvation, to take a team of his fittest men and attempt to find help. Setting out in appalling conditions with hopelessly inadequate equipment, they endured all weather and terrain and finally reached safety. Persuading a local team of his confidence that the abandoned team would still be alive, he set out again to find them. After almost 2 years trapped on the ice, all members of the crew were finally rescued.', NULL, NULL, 0.4991, 7.0, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
