INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3694, 409421, 'tt6574146', NULL, 'BLAME!', 'ブラム', 'movie', 2017, 'https://image.tmdb.org/t/p/w500/7eoRQY7VUMawwBnuD6uwN4szc8k.jpg', 'https://image.tmdb.org/t/p/original/9orgGrjh0Jivz0zZLn1Ufj4NRZP.jpg', 'In the distant technological future, civilization has reached its ultimate Net-based form. An "infection" in the past caused the automated systems to spiral out of order, resulting in a multi-leveled city structure that replicates itself infinitely in all directions. Now humanity has lost access to the city''s controls, and is hunted down and purged by the defense system known as the Safeguard. In a tiny corner of the city, a little enclave known as the Electro-Fishers is facing eventual extinction, trapped between the threat of the Safeguard and dwindling food supplies. A girl named Zuru goes on a journey to find food for her village, only to inadvertently cause doom when an observation tower senses her and summons a Safeguard pack to eliminate the threat. With her companions dead and all escape routes blocked, the only thing that can save her now is the sudden arrival of Killy the Wanderer, on his quest for the Net Terminal Genes, the key to restoring order to the world.', NULL, NULL, 1.5145, 6.54, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
