INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3707, 2487, 'tt0158714', NULL, 'Lady Snowblood', '修羅雪姫', 'movie', 1973, 'https://image.tmdb.org/t/p/w500/wkcbaqCoYEXDUnSQ6NTnB2C7H05.jpg', 'https://image.tmdb.org/t/p/original/u2fkLndVDFA0ie4a8k6GpWWsm0N.jpg', 'Yuki''s family is nearly wiped out before she is born due to the machinations of a band of criminals. These criminals kidnap and brutalize her mother but leave her alive. Later her mother ends up in prison with only revenge to keep her alive. She creates an instrument for this revenge by purposefully getting pregnant. Yuki never knows the love of a family but only killing and revenge.', NULL, NULL, 1.1177, 7.52, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3708, 198375, 'tt2591814', NULL, 'The Garden of Words', '言の葉の庭', 'movie', 2013, 'https://image.tmdb.org/t/p/w500/mXUCVq3HMtS4Y9IQ8vmEOPyN0vH.jpg', 'https://image.tmdb.org/t/p/original/qMNmdJG0WFNXcI6hfZMQH0geHc5.jpg', 'Takao, who is training to become a shoemaker, skipped school and is sketching shoes in a Japanese-style garden. He meets a mysterious woman, Yukino, who is older than him. Then, without arranging the times, the two start to see each other again and again, but only on rainy days. They deepen their relationship and open up to each other. But the end of the rainy season soon approaches.', NULL, NULL, 2.7903, 7.6, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3709, 4550, 'tt0451094', NULL, 'Lady Vengeance', '친절한 금자씨', 'movie', 2005, 'https://image.tmdb.org/t/p/w500/3Oy3iLMqD79us2iAUD6fKqWebYU.jpg', 'https://image.tmdb.org/t/p/original/wP1nu98mgiSOyuPmMWdZ8109S9j.jpg', 'Released after being wrongfully convicted and imprisoned for 13 years, a woman begins executing her elaborate plan of retribution.', NULL, NULL, 2.1793, 7.52, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3710, 1566269, 'tt39089423', NULL, 'The First Snow of Fraggle Rock', 'The First Snow of Fraggle Rock', 'movie', 2025, 'https://image.tmdb.org/t/p/w500/xyxAOTToALUkeFS9x5V6MOv8YWr.jpg', 'https://image.tmdb.org/t/p/original/h5hCdU9KvcCbBihSNfn3vtML7tV.jpg', 'When the holidays are filled with unexpected adventures and challenges, the Fraggles learn to appreciate each day for being unique and special, like a snowflake.', NULL, NULL, 3.9533, 7.0, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3711, 47002, 'tt0113703', NULL, 'Love Letter', 'ラブレター', 'movie', 1995, 'https://image.tmdb.org/t/p/w500/9iAgQSkt9z34DTYQfpG0M69SyiL.jpg', 'https://image.tmdb.org/t/p/original/j0H799tVVLesjskDbL5FKcV5Nfr.jpg', 'Hiroko attends the memorial service of her fiancé, Itsuki Fujii, who died in a mountain-climbing incident. Although Itsuki''s mother says that their old house is gone, Hiroko records the address listed under his name in his yearbook and sends him a letter. Surprisingly, she receives a reply, and discovers it came from his old classmate, a girl who also happens to be called Itsuki Fujii.', NULL, NULL, 2.3456, 7.8, 0, 14.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3712, 851418, NULL, NULL, 'Days In Between', 'Days In Between', 'movie', 2015, 'https://image.tmdb.org/t/p/w500/Gz5l1WhtYEVawqKLI6YXvWNfXO.jpg', NULL, 'For the essay film “Days In Between” Marianna Christofides has been recursively visiting the Balkans for the past four years, at first seeking out sites along borders lying by rivers and lakes, where the course of the boundary remains indefinite. After having lost the entire first block of footage, the data on the hard drive not being retrievable, she sets out anew, only to witness that the places do not exist anymore in the same way. Topography changes insomuch that landscapes seem to vanish and observations “antiquate”. The approach of the film extends accordingly, now focusing on loss, omissions, disappearances without trace. The spiralling vacuum of stereotypes and metaphors, the appropriation of geological terms in political parlance that characterize the gaze of the West onto the region comes to the fore. Rivers become amphibious, both solid and liquid, as they separate bank from bank whilst connecting along their course.', NULL, NULL, 0.0, 0.0, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
