INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3723, 2502, 'tt0372183', NULL, 'The Bourne Supremacy', 'The Bourne Supremacy', 'movie', 2004, 'https://image.tmdb.org/t/p/w500/jupG9sFT64YwM8PSkwkUD2wHcYD.jpg', 'https://image.tmdb.org/t/p/original/fE7RqvVHbGHjBC9NjIjlLh2t4zK.jpg', 'A CIA operation to purchase classified Russian documents is blown by a rival agent, who then shows up in the sleepy seaside village where Bourne and Marie have been living. The pair run for their lives and Bourne, who promised retaliation should anyone from his former life attempt contact, is forced to once again take up his life as a trained assassin to survive.', NULL, NULL, 4.4817, 7.333, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3724, 10463, 'tt0128385', NULL, 'Eastern Cross', 'Ostkreuz', 'movie', 1991, 'https://image.tmdb.org/t/p/w500/3CElS8uCWJJWMHKkz0mTsvDFnke.jpg', 'https://image.tmdb.org/t/p/original/e8VeOHoyG5SQ3vqC1r65Bg1HjTR.jpg', '15-year-old Elfie literally and metaphorically inhabits a no-man’s-land between the two Germanies shortly after the fall of the Berlin Wall. The film deploys a neorealist aesthetic to reinforce the difficulties confronting the girl, and by inference, Germany.', NULL, NULL, 0.3871, 6.7, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3725, 408292, 'tt5936692', NULL, 'The Last Family', 'Ostatnia rodzina', 'movie', 2016, 'https://image.tmdb.org/t/p/w500/zkdH8b7gt5Pr6c4n2s9AiSv9lzq.jpg', 'https://image.tmdb.org/t/p/original/cLj1rpBxQU35G8lAn8WxQygBy3D.jpg', 'Beksiński is a gentle man with arachnophobia, despite his hardcore sexual fantasies and his fondness for painting disturbing dystopian works. Beksiński is a family man who wants only the best for his loving wife Zofia, neurotic son Tomasz and the couple''s aging mothers. His daily painting to classical music eventually pays off and he makes a name for himself in contemporary art. Good Catholic woman Zofia tries to hold the family together, but troubled son Tomasz proves to be a handful with his violent outbursts and suicidal threats. Their relief is brief when he starts dating women and becomes a radio presenter and movie translator, and the concerned parents must be on constant watch to prevent their son from hurting himself. But Beksiński never believed that family life would always be sunshine and rainbows. As he tapes everything with his beloved camcorder, the 28-year Beksiński saga unfolds through paintings, near-death experiences, dance music trends and funerals...', NULL, NULL, 0.5329, 7.138, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3726, 988397, 'tt31691389', NULL, 'Universal Language', 'Une langue universelle', 'movie', 2024, 'https://image.tmdb.org/t/p/w500/wS5pdSFLjzFzBCwa8kTE368jb4U.jpg', 'https://image.tmdb.org/t/p/original/A0FeRPihXjMDN9bdoKsOzIC7zl6.jpg', 'Winter. Somewhere between Tehran and Winnipeg. Negin and Nazgol find a sum of money frozen deep within the sidewalk ice and try to find a way to get it out. Massoud leads a group of befuddled tourists upon an increasingly-strange walking tour of Winnipeg historic sites. Matthew leaves his job at the Québec government and embarks upon a mysterious journey to visit his estranged mother.', NULL, NULL, 1.0619, 7.053, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
