INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3755, 13570, 'tt0080040', NULL, 'Tourist Trap', 'Tourist Trap', 'movie', 1979, 'https://image.tmdb.org/t/p/w500/c19pSkUfNElrmVn0iYtiJys5dK8.jpg', 'https://image.tmdb.org/t/p/original/zOfIcQhwElCp0tLX0dU02wJq3Nj.jpg', 'After their car breaks down, a group of young travelers find themselves stranded at a roadside museum run by the enigmatic Mr. Slausen and populated by his collection of life-like wax mannequins.', NULL, NULL, 0.6709, 6.1, 0, 12.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3756, 250574, 'tt2428170', NULL, 'Creep', 'Creep', 'movie', 2014, 'https://image.tmdb.org/t/p/w500/qn53D574tT0YRyLgirEFHQwGUXw.jpg', 'https://image.tmdb.org/t/p/original/AvrGwToWkP6fp13lzpxsyzoq9JH.jpg', 'Looking for work, Aaron comes across a cryptic online ad: “$1,000 for the day. Filming service. Discretion is appreciated.” Low on cash and full of naiveté, he decides to go for it. He drives to a cabin in a remote mountain town where he meets Josef, his cinematic subject for the day. Josef is sincere and the project seems heartfelt, so Aaron begins to film. But as the day goes on, it becomes clear that Josef is not who he says, and his intentions are not at all pure.', NULL, NULL, 3.9844, 6.398, 0, 22.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3757, 396493, 'tt3654796', NULL, 'Creep 2', 'Creep 2', 'movie', 2017, 'https://image.tmdb.org/t/p/w500/a0m7WciFnBqpcyH1Yi8i4tdvk0k.jpg', 'https://image.tmdb.org/t/p/original/xn4qe52O0gwfapVT9aOZOPA4wQt.jpg', 'After finding an ad online for “video work,” Sara, a video artist whose primary focus is creating intimacy with lonely men, thinks she may have found the subject of her dreams. She drives to a remote house in the forest and meets a man claiming to be a serial killer. Unable to resist the chance to create a truly shocking piece of art, she agrees to spend the day with him. However, as the day goes on, she discovers she may have dug herself into a hole from which she can’t escape.', NULL, NULL, 2.0315, 6.335, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
