INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3768, NULL, NULL, 7351, 'Doom', 'Doom', 'game', 2016, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1nc7.jpg', NULL, 'Developed by id software, the studio that pioneered the first-person shooter genre and created multiplayer Deathmatch, Doom returns as a brutally fun and challenging modern-day shooter experience. Relentless demons, impossibly destructive guns, and fast, fluid movement provide the foundation for intense, first-person combat – whether you’re obliterating demon hordes through the depths of Hell in the single-player campaign, or competing against your friends in numerous multiplayer modes. Expand your gameplay experience using Doom SnapMap game editor to easily create, play, and share your content with the world.', 'https://www.igdb.com/games/doom--2', '["PlayStation 4", "PC (Microsoft Windows)", "Xbox One"]', NULL, NULL, 0, 3.5, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3769, NULL, NULL, 1051, 'Mirror''s Edge', 'Mirror''s Edge', 'game', 2008, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5gbw.jpg', NULL, 'Mirror''s Edge is a first-person action-adventure game focused on parkour and free-running. Set in a heavily surveilled city, players control Faith, a courier who traverses rooftops using wall-runs, jumps, and slides to deliver sensitive information. The gameplay emphasizes momentum and fluid movement over combat, with a focus on finding the fastest path through urban environments.', 'https://www.igdb.com/games/mirror-s-edge', '["PlayStation 3", "PC (Microsoft Windows)", "Xbox 360"]', NULL, NULL, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3770, NULL, NULL, 2112, 'Mirror''s Edge Catalyst', 'Mirror''s Edge Catalyst', 'game', 2016, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co28r2.jpg', NULL, 'Mirror''s Edge Catalyst is an action-adventure game and the reboot to Mirror''s Edge. The story in the game explores the past of the protagonist Faith. Like in the previous game, the main gameplay in Mirror''s Edge Catalyst involves traversing the city using parkour to reach certain objectives. Unlike the linear levels in Mirror''s Edge, Mirror''s Edge Catalyst features an open-world free-roaming environment. Combat has been overhauled and emphasized compared to the first game and Catalyst no longer allows the player to use weapons, instead focusing on melee attacks.', 'https://www.igdb.com/games/mirrors-edge-catalyst', '["PlayStation 4", "PC (Microsoft Windows)", "Xbox One"]', NULL, NULL, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
