INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3772, NULL, NULL, 141538, 'The Callisto Protocol', 'The Callisto Protocol', 'game', 2022, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ymo.jpg', NULL, 'In this narrative-driven, third-person survival horror game set 300 years in the future, the player will take on the role of Jacob Lee – a victim of fate thrown into Black Iron Prison, a maximum-security penitentiary located on Jupiter''s moon, Callisto. When inmates begin to transform into monstrous creatures, the prison is thrown into chaos.', 'https://www.igdb.com/games/the-callisto-protocol', '["Xbox Series X|S", "PlayStation 4", "PC (Microsoft Windows)", "PlayStation 5", "Xbox One"]', NULL, NULL, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3773, NULL, NULL, 250617, 'Ghostrunner II', 'Ghostrunner II', 'game', 2023, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co97mh.jpg', NULL, 'Ghostrunner II is a hardcore FPP slasher set in a post-apocalyptic, cyberpunk world. Featuring everything fans loved about Ghostrunner plus incredible boss fights, new interactive story, thrilling motorbike levels, improved skills, and more cyber ninja action.', 'https://www.igdb.com/games/ghostrunner-ii', '["Xbox Series X|S", "PC (Microsoft Windows)", "PlayStation 5"]', NULL, NULL, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
