INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3779, NULL, NULL, 19564, 'Death Stranding', 'Death Stranding', 'game', 2019, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobksf.jpg', NULL, 'Death Stranding is an action game set in a post-apocalyptic United States.

Players control Sam Porter Bridges, a courier tasked with reconnecting isolated cities via a communication network while delivering essential cargo. The gameplay blends traversal, resource management, and narrative elements, with a focus on social connectivity through asynchronous multiplayer. It is known for its unique mechanics, atmospheric world, and philosophical themes.', 'https://www.igdb.com/games/death-stranding', '["PlayStation 4", "PC (Microsoft Windows)"]', NULL, NULL, 0, 6.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
