The game includes the complete Halo 3 multiplayer map collection, with three additional maps, and introduces Firefight, a cooperative mode in which players face waves of Covenant enemies.', 'https://www.igdb.com/games/halo-3-odst', '["PC (Microsoft Windows)", "Xbox 360", "Xbox One"]', NULL, NULL, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3782, NULL, NULL, 990, 'Halo: Reach', 'Halo: Reach', 'game', 2010, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xha.jpg', NULL, 'Halo: Reach is a first-person shooter set in 2552, serving as a prequel to Halo: Combat Evolved. Players control Noble Six, a member of Noble Team, an elite squad of Spartan supersoldiers defending the human colony world of Reach from a Covenant invasion. The game features campaign gameplay playable solo or cooperatively, with armor abilities replacing single-use equipment from previous entries. Multiplayer includes competitive modes, a Firefight survival mode, and Forge World, a large-scale level editor. The game also introduces space combat dogfight sequences to the series.', 'https://www.igdb.com/games/halo-reach', '["PC (Microsoft Windows)", "Xbox 360", "Xbox One"]', NULL, NULL, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3783, NULL, NULL, 17447, 'Titanfall 2', 'Titanfall 2', 'game', 2016, 'https://images.igdb.com/igdb/image/upload/t_cover_big/fhbeilnghyhhmjqhinqa.jpg', NULL, 'Titanfall 2 is a first-person shooter with both a single-player campaign and competitive multiplayer. The campaign follows a Militia rifleman who bonds with a Titan, a large bipedal mech, after his pilot is killed. Gameplay combines fast-paced infantry movement, including wall-running and double-jumping, with sections where the player controls the Titan in combat. Multiplayer features team-based modes with players fighting as both Pilots and Titans on the same battlefield.', 'https://www.igdb.com/games/titanfall-2', '["PlayStation 4", "PC (Microsoft Windows)", "Xbox One"]', NULL, NULL, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
