INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3786, NULL, NULL, 96437, 'Starfield', 'Starfield', 'game', 2023, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co39vv.jpg', NULL, 'Starfield is a single-player action role-playing game developed by Bethesda Game Studios and set in an open-world space environment. Players create a customizable character and explore a region of the Milky Way galaxy spanning approximately 50 light-years, landing on over 1,000 planets with procedurally generated landscapes. Gameplay includes first-person and third-person combat using firearms, explosives, and melee weapons, as well as spaceship construction, outpost building, resource gathering, and crafting. Players recruit companion characters, join factions, and progress through skill trees spanning Physical, Social, Combat, Science, and Tech categories.', 'https://www.igdb.com/games/starfield', '["Xbox Series X|S", "PC (Microsoft Windows)", "PlayStation 5"]', NULL, NULL, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3787, NULL, NULL, 72, 'Portal 2', 'Portal 2', 'game', 2011, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rs4.jpg', NULL, 'Sequel to the acclaimed Portal (2007), Portal 2 pits the protagonist of the original game, Chell, and her new robot friend, Wheatley, against more puzzles conceived by GLaDOS, an A.I. with the sole purpose of testing the Portal Gun''s mechanics and taking revenge on Chell for the events of Portal. As a result of several interactions and revelations, Chell once again pushes to escape Aperture Science Labs.', 'https://www.igdb.com/games/portal-2', '["PlayStation 3", "Linux", "PC (Microsoft Windows)", "Mac", "Xbox 360", "Nintendo Switch"]', NULL, NULL, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
