INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3790, NULL, NULL, 280, 'Doom 3', 'Doom 3', 'game', 2004, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v3n.jpg', NULL, 'A massive demonic invasion has overwhelmed the Union Aerospace Corporation''s (UAC) Mars Research Facility, leaving only chaos and horror in its wake. As one of only a few survivors, you must fight your way to hell and back against a horde of evil monsters. The path is dark and dangerous, but you''ll have an array of weapons--including a pistol, a chainsaw, grenades, and more--to use for protection.', 'https://www.igdb.com/games/doom-3', '["Xbox", "Linux", "PC (Microsoft Windows)", "Mac"]', NULL, NULL, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3791, NULL, NULL, 103298, 'Doom Eternal', 'Doom Eternal', 'game', 2020, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3p5n.jpg', NULL, 'Doom Eternal is a first-person shooter developed by id Software and the sequel to Doom (2016). Players control the Doom Slayer as he fights to end a demonic invasion of Earth. Combat is built around aggressive resource management, where health, armor, and ammo are gained by executing, igniting, or chainsawing enemies. The game introduces platforming segments, destructible enemy weak points, an expanded weapon arsenal, and a multiplayer mode called Battlemode, where one player-controlled Slayer fights two player-controlled demons.', 'https://www.igdb.com/games/doom-eternal', '["Google Stadia", "Xbox Series X|S", "PlayStation 4", "PC (Microsoft Windows)", "PlayStation 5", "Xbox One", "Nintendo Switch"]', NULL, NULL, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3792, NULL, NULL, 509, 'Rage', 'Rage', 'game', 2011, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ybv.jpg', NULL, 'Rage is a first-person shooter set in the not-too-distant future after an asteroid impacts Earth, leaving a ravaged world behind. You emerge into this vast wasteland to discover humanity working to rebuild itself against such forces as raider gangs, mutants, and the Authority – an oppressive government regime that has a special interest in you in particular.', 'https://www.igdb.com/games/rage', '["PlayStation 3", "PC (Microsoft Windows)", "Mac", "Xbox 360"]', NULL, NULL, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3793, NULL, NULL, 101211, 'Rage 2', 'Rage 2', 'game', 2019, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rbm.jpg', NULL, 'Dive headfirst into a dystopian world devoid of society, law, and order. Rage 2 brings together a true open world FPS experience where you can go anywhere, shoot anything, and explode everything.', 'https://www.igdb.com/games/rage-2', '["Google Stadia", "PlayStation 4", "PC (Microsoft Windows)", "Xbox One"]', NULL, NULL, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3794, NULL, NULL, 2552, 'Mad Max', 'Mad Max', 'game', 2015, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1uuh.jpg', NULL, 'In Mad Max, the player takes on the role of titular character Mad Max; a dangerous melee fighter and can use his attacks to kill almost anyone. His weapon of choice is his shotgun. He is assisted by another man called Chumbucket. Chum mainly works with Max to build and upgrade the Magnum Opus vehicle.

Mad Max will feature a variety of weapons which Max can use to defeat enemies. Though the shotgun is Max''s weapon of choice, ammo is scarce, and so melee options are the smarter way to go. The ''thunderstick'' is an explosive weapon that can be lanced into an enemy''s chest, crackling like a lit dynamite fuse before blowing the victim to smithereens. The Harpoon is also one of Max''s favorite weapon though it can only be used in-vehicle with Chum riding along. Max''s Magnum Opus can be combined with a speedy V12 engine and powerful ramming ability to destroy enemies''s vehicles and weaponry. When simultaneously driving and aiming, the game enters slow-motion and allows you to toggle between targets. Not much is known about the vehicular combat and its features.

Mad Max will feature crafting system which can be used to craft new weapons and tools. Max''s garage can also be used to change and modify the car''s engines, chassis, wheels, body works including paint treatment and the “shell” of the auto-mobile and the car’s weight and attributes update accordingly. Max can also be upgraded though it''s plans hasn''t fully been implemented.

Many choices are given in the game, such as, either playing silently or aggressively. Max can also get guidance from Chum about how he can complete his objectives strategically. However, its largely up to the player how he can complete the objectives.', 'https://www.igdb.com/games/mad-max', '["PlayStation 4", "Linux", "PC (Microsoft Windows)", "Mac", "Xbox One"]', NULL, NULL, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3795, NULL, NULL, 749, 'Homeworld', 'Homeworld', 'game', 1999, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coc6i8.jpg', NULL, 'Homeworld is a 3D real-time strategy game set in space and focusing on the conflict between the Kushan, who are attempting to locate their long-lost homeworld, and the Taiidan Empire which is trying to destroy them.', 'https://www.igdb.com/games/homeworld', '["Linux", "PC (Microsoft Windows)", "Mac"]', NULL, NULL, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
