INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3846, 137113, 'tt1631867', NULL, 'Edge of Tomorrow', 'Edge of Tomorrow', 'movie', 2014, 'https://image.tmdb.org/t/p/w500/nBM9MMa2WCwvMG4IJ3eiGUdbPe6.jpg', 'https://image.tmdb.org/t/p/original/4V1yIoAKPMRQwGBaSses8Bp2nsi.jpg', 'Major Bill Cage is an officer who has never seen a day of combat when he is unceremoniously demoted and dropped into combat. Cage is killed within minutes, managing to take an alpha alien down with him. He awakens back at the beginning of the same day and is forced to fight and die again... and again - as physical contact with the alien has thrown him into a time loop.', NULL, NULL, 12.071, 7.641, 0, 6.33333333333333303e+00, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3847, 592230, 'tt7394674', NULL, 'Blood Quantum', 'Blood Quantum', 'movie', 2019, 'https://image.tmdb.org/t/p/w500/pQnfrys3nyOpUxktxK2CBnm7Rv8.jpg', 'https://image.tmdb.org/t/p/original/xg1adjc8iEsQ4znJNjUQSvuiPjr.jpg', 'The dead are coming back to life outside the isolated Mi''kmaq reserve of Red Crow, except for its Indigenous inhabitants who are strangely immune to the zombie plague.', NULL, NULL, 1.084, 5.8, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3848, NULL, NULL, 6801, 'Far Cry 4', 'Far Cry 4', 'game', 2014, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2npa.jpg', NULL, 'Discover the most diverse Far Cry world ever created. With terrain spanning from lush forests to the snowcapped Himalayas, the entire world is alive… and deadly. From leopards, rhinos, black eagles, and vicious honey badgers, Kyrat is home to abundant wildlife. As you embark on your hunt for resources, know that something may be hunting you...

Scout enemy territory from above in the all-new gyrocopter and then plummet back to earth in your wing suit. Climb aboard the back of a six-ton elephant and unleash its raw power on your enemies. Choose the right weapon for the job, no matter how insane or unpredictable that job might be. With a diverse arsenal, you’ll be prepared for anything.', 'https://www.igdb.com/games/far-cry-4', '["Google Stadia", "Xbox Series X|S", "PlayStation 3", "PlayStation 4", "PC (Microsoft Windows)", "PlayStation 5", "Xbox 360", "Xbox One"]', NULL, NULL, 0, 9.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3849, 76492, 'tt0837562', NULL, 'Hotel Transylvania', 'Hotel Transylvania', 'movie', 2012, 'https://image.tmdb.org/t/p/w500/eJGvzGrsfe2sqTUPv5IwLWXjVuR.jpg', 'https://image.tmdb.org/t/p/original/5rARlA8beRAVXPYzSaF2NoS8Ry5.jpg', 'Welcome to Hotel Transylvania, Dracula''s lavish five-stake resort, where monsters and their families can live it up and no humans are allowed. One special weekend, Dracula has invited all his best friends to celebrate his beloved daughter Mavis''s 118th birthday. For Dracula catering to all of these legendary monsters is no problem but the party really starts when one ordinary guy stumbles into the hotel and changes everything!', NULL, NULL, 12.579, 6.967, 0, 9.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3850, NULL, NULL, 2939, 'The Vanishing of Ethan Carter', 'The Vanishing of Ethan Carter', 'game', 2014, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1r7q.jpg', NULL, 'In The Vanishing of Ethan Carter, you play as Paul Prospero, an occult detective who receives a disturbing letter from Ethan Carter and realizes that the boy is in grave danger. When Paul arrives in Ethan''s home of Red Creek Valley, he realizes things are even worse than he imagined. Ethan has vanished in the wake of a brutal murder, which Paul comes to see might not be the only murder to investigate. Using both regular and supernatural detective skills, Paul must figure out what happened to the missing boy.', 'https://www.igdb.com/games/the-vanishing-of-ethan-carter', '["PlayStation 4", "PC (Microsoft Windows)", "Xbox One", "Nintendo Switch"]', NULL, NULL, 0, 9.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3851, 335977, 'tt1462764', NULL, 'Indiana Jones and the Dial of Destiny', 'Indiana Jones and the Dial of Destiny', 'movie', 2023, 'https://image.tmdb.org/t/p/w500/Af4bXE63pVsb2FtbW8uYIyPBadD.jpg', 'https://image.tmdb.org/t/p/original/57JocxmicOoAMhkUSmdKBlpZWMT.jpg', 'Finding himself in a new era, and approaching retirement, Indy wrestles with fitting into a world that seems to have outgrown him. But as the tentacles of an all-too-familiar evil return in the form of an old rival, Indy must don his hat and pick up his whip once more to make sure an ancient and powerful artifact doesn''t fall into the wrong hands.', NULL, NULL, 5.4218, 6.511, 0, 10.5, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3852, 54794, 'tt0295303', NULL, 'Heartlands', 'Heartlands', 'movie', 2003, 'https://image.tmdb.org/t/p/w500/1KDKC1r7QTyzGNS5a7v33VQg4HY.jpg', NULL, 'Gentle Colin ''Col'' Lawes happily lead a quiet life, running a news agency with his soiled-rotten wife Sandra and playing competition darts in the Atletic Arms team. Colin catches her committing adultery with team captain Geoff, a cop, who pretends Colin abused her. Col is thrown off the team just after it qualified for the league finals in Blackpool. He decides to travel there alone, hoping to win her back.', NULL, NULL, 0.8635, 6.0, 0, 9.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3853, 1161680, 'tt19287686', NULL, 'A Whole Life', 'Ein ganzes Leben', 'movie', 2023, 'https://image.tmdb.org/t/p/w500/podcOble2lPYMQoBIwBPYaHtGhy.jpg', 'https://image.tmdb.org/t/p/original/823bFEITN9k0d6LV1AtNlPtpDZF.jpg', 'When Andreas arrives in the remote valley in the Austrian Alps, he is only about four years old - nobody knows for sure. He grows up to become a skilled farmhand and, as a young man, joins a work crew that builds one of the first mountain railroads, bringing light and noise to the valley along with electricity. He also finds the love of his life in Marie, but their happiness is short-lived. Only many years later, when Andreas embarks on his final journey, she is with him once again. And in amazement Andreas looks back at all the years that lie behind him.', NULL, NULL, 0.6048, 6.971, 0, 10.5, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3854, 232572, 'tt1178665', NULL, 'A Walk in the Woods', 'A Walk in the Woods', 'movie', 2015, 'https://image.tmdb.org/t/p/w500/zJmNuWakSSaJvywYyxZIS9EGWPN.jpg', 'https://image.tmdb.org/t/p/original/oXj7C4IuTTtA2iR7hCYtGRy0BS1.jpg', 'After spending two decades in England, Bill Bryson returns to the U.S., where he decides the best way to connect with his homeland is to hike the Appalachian Trail with one of his oldest friends.', NULL, NULL, 2.2868, 6.116, 0, 9.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3855, NULL, NULL, 21604, 'Old Man''s Journey', 'Old Man''s Journey', 'game', 2017, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22s9.jpg', NULL, 'Old Man’s Journey, a soul-searching puzzle adventure, tells a story of life, loss, reconciliation, and hope. Entrenched in a beautifully sunkissed and handcrafted world, embark on a heartfelt journey interwoven with lighthearted and pressure-free puzzle solving.

During this compact gameplay experience, you’ll be transported to a vibrant and wishful world, exploring life’s complexities through the old man’s eyes. Meditatively delightful and reflective, Old Man’s Journey invites you to immerse yourself in quiet and inquisitive puzzles, and experience the old man’s heartache, regret, and hope.', 'https://www.igdb.com/games/old-mans-journey', '["PlayStation 4", "Android", "PC (Microsoft Windows)", "iOS", "Mac", "Xbox One", "Nintendo Switch"]', NULL, NULL, 0, 9.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
