INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3891, 1422041, 'tt35511966', NULL, 'La Bola Negra', 'La bola negra', 'movie', 2026, 'https://image.tmdb.org/t/p/w500/du0WFunZDoFqddLa8G1vk4o0Y0c.jpg', 'https://image.tmdb.org/t/p/original/poQ9cHZpNVUfBc1Vw9MOIwRZyvY.jpg', 'Set across three timelines — Republican Spain in 1932, the Civil War in 1937, and contemporary Spain in 2017 — the film follows a constellation of interconnected lives centered on three young men, whose emotional and political echoes gradually reveal themselves.', NULL, NULL, 2.9405, 0.0, 0, 9.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3892, 18734, 'tt0242587', NULL, 'L.I.E.', 'L.I.E.', 'movie', 2001, 'https://image.tmdb.org/t/p/w500/ck5Tkq17M6khEN7JQlQznoYl37L.jpg', 'https://image.tmdb.org/t/p/original/zmKvbUUnTQMMUdKfd8FA4J6DSgK.jpg', 'With his mother dead and his father busy at work, Howie feels adrift in his New York suburb. He and his friend Gary spend their time burglarizing their neighbors'' homes — until they make the mistake of robbing the house of Big John, a macho former Marine who is also an unrepentant pedophile. He propositions Howie, who declines, but the two eventually develop an unlikely and dangerous friendship.', NULL, NULL, 1.0982, 6.724, 0, 9.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3893, 14626, 'tt0209933', NULL, 'Beau Travail', 'Beau Travail', 'movie', 2000, 'https://image.tmdb.org/t/p/w500/5ySa1aQaT7kMcAbKwlS1HXxp2hM.jpg', 'https://image.tmdb.org/t/p/original/1C84Yg3F2CgGJlOilvXBP8OZCMB.jpg', 'Foreign Legion officer Galoup recalls his once glorious life, training troops in the Gulf of Djibouti. His existence there was happy, strict and regimented, until the arrival of a promising young recruit, Sentain, plants the seeds of jealousy in Galoup''s mind.', NULL, NULL, 0.8026, 7.126, 0, 11.5, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3894, 27069, 'tt0390418', NULL, 'The Raspberry Reich', 'The Raspberry Reich', 'movie', 2004, 'https://image.tmdb.org/t/p/w500/xv0crpl366W0OHPFHHpBFX8Sn5e.jpg', 'https://image.tmdb.org/t/p/original/bTe3K2uuI8poKAuTXd3DujzCOEN.jpg', 'Gudrun has modeled her amateur German terrorist group after the 1970s Red Army Faction (Baader-Meinhof Gang). She attempts to imitate her heroes by kidnapping the son of a wealthy industrialist and hopes to negotiate leftist demands from the father. When Gudrun’s not spouting leftist verses (including during a hilariously brilliant fuck session), she’s trying to convince her all-male gang to abandon their heterosexuality, which she believes is the result of mass delusion.', NULL, NULL, 0.8013, 5.6, 0, 9.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3895, 173535, 'tt0240898', NULL, 'The Silver Surfer', 'The Silver Surfer', 'movie', 1993, 'https://image.tmdb.org/t/p/w500/zrnm91UqqFjGvkbrp2l6XUs3Jqd.jpg', NULL, 'NASA Deep Space Tracking Facility: Radar is picking something up. An object heading towards earth, L.A., at near light-speed. Impact: 9 seconds. L.A.: A boy, not even 10 years old, is being chased by three older boys. He is holding something small, a ''Terminator'' figurine. Dead end! A fence is blocking his way. He is trapped. Standing no chance he hands ''Arnie'' over to the gang leader. NASA Deep Space Tracking Facility: Impact! Three... Two... One... ?... Nothing. L.A.: The bullies are leaving the crime scene, now proud owners of an ''Arnie'' figurine. But something''s happening, something is blocking their way... a man clad in silver, hovering on a surfboard...', NULL, NULL, 0.3721, 5.2, 0, 8.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3896, 73, 'tt0120586', NULL, 'American History X', 'American History X', 'movie', 1998, 'https://image.tmdb.org/t/p/w500/x2drgoXYZ8484lqyDj7L1CEVR4T.jpg', 'https://image.tmdb.org/t/p/original/6qHI1IYj7QlLSCwHRzkL62X175s.jpg', 'Derek Vineyard is paroled after serving 3 years in prison for killing two African-American men. Through his brother, Danny Vineyard''s narration, we learn that before going to prison, Derek was a skinhead and the leader of a violent white supremacist gang that committed acts of racial crime throughout L.A. and his actions greatly influenced Danny. Reformed and fresh out of prison, Derek severs contact with the gang and becomes determined to keep Danny from going down the same violent path as he did.', NULL, NULL, 8.4131, 8.327, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3897, 25, 'tt0418763', NULL, 'Jarhead', 'Jarhead', 'movie', 2005, 'https://image.tmdb.org/t/p/w500/6vdj47RAWOUZBkeQmqToeZ7eaio.jpg', 'https://image.tmdb.org/t/p/original/bQ8fRUaitJvi54O2lUT6Ta7FVHK.jpg', 'Jarhead is a film about a US Marine Anthony Swofford’s experience in the Gulf War. After putting up with an arduous boot camp, Swofford and his unit are sent to the Persian Gulf where they are eager to fight, but are forced to stay back from the action. Swofford struggles with the possibility of his girlfriend cheating on him, and as his mental state deteriorates, his desire to kill increases.', NULL, NULL, 2.3245, 6.688, 0, 12.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
