INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3905, 9678, 'tt0185431', NULL, 'Little Nicky', 'Little Nicky', 'movie', 2000, 'https://image.tmdb.org/t/p/w500/AudA8gnTWSBWXBHSBHnr3HHUXXM.jpg', 'https://image.tmdb.org/t/p/original/fYKfPWArkWeMcril9JxhVRP9bYk.jpg', 'After the lord of darkness decides he will not cede his throne to any of his three sons, the two most powerful of them escape to Earth to create a kingdom for themselves. This action closes the portal filtering sinful souls to Hell and causes Satan to wither away. He must send his most weak but beloved son, Little Nicky, to Earth to return his brothers to Hell.', NULL, NULL, 2.8254, 5.846, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
