INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3921, 16172, 'tt0145893', NULL, 'Simply Irresistible', 'Simply Irresistible', 'movie', 1999, 'https://image.tmdb.org/t/p/w500/zFsqqPQUz69wPaLBqQeiGbGiW7J.jpg', 'https://image.tmdb.org/t/p/original/qIDYvZBLYLuWtKnSgq1okHU3Nt8.jpg', 'After her mother''s death, mediocre chef Amanda Shelton is having trouble attracting customers to her family''s restaurant. While shopping for ingredients, she is given a magical crab by mysterious Gene O''Reilly. Afterward, Amanda''s dishes suddenly become excellent, inducing strong emotional reactions in everyone who eats them. Tom Bartlett, who is preparing to open his own eatery, tries her cooking and falls in love.', NULL, NULL, 1.8385, 5.469, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3922, 9715, 'tt0119313', NULL, 'Hope Floats', 'Hope Floats', 'movie', 1998, 'https://image.tmdb.org/t/p/w500/6PRFM09xjGSWpXObW87CT5JELGJ.jpg', 'https://image.tmdb.org/t/p/original/9zgnuwIK6JAc6giVsscq9H82li1.jpg', 'Birdee Pruitt has been humiliated on live television by her best friend, Connie, who''s been sleeping with Birdee''s husband, Bill. Birdee tries starting over with her daughter, Bernice, by returning to her small Texas hometown, but she''s faced with petty old acquaintances who are thrilled to see Birdee unhappy -- except for her friend Justin. As he helps Birdee get back on her feet, love begins to blossom.', NULL, NULL, 1.7876, 6.432, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
