INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3925, 6964, 'tt0337741', NULL, 'Something''s Gotta Give', 'Something''s Gotta Give', 'movie', 2003, 'https://image.tmdb.org/t/p/w500/1cpdqe0SpiHzzbOLq9GDUUlZdSl.jpg', 'https://image.tmdb.org/t/p/original/xTQXtSQQZY5ZbJ1GxEcSCRP4aWV.jpg', 'When perpetually single, aging music industry exec Harry Sanborn, and his latest trophy girlfriend, Marin, arrive at her mother''s beach house in the Hamptons, they find that her mother, playwright Erica Barry, also plans to stay for the weekend. Erica is scandalized by the relationship and Harry''s sexist ways. But when Harry has a heart attack while there, and the doctor prescribes bedrest, his only option is to stay at the Barry home. Left in the care of Erica and his doctor, a love triangle starts to take shape.', NULL, NULL, 2.5101, 6.631, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
