INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3929, 2621, 'tt0122459', NULL, 'Return to Me', 'Return to Me', 'movie', 2000, 'https://image.tmdb.org/t/p/w500/mtYZyZh7hSiTq3gAU0C8FlcMC5.jpg', 'https://image.tmdb.org/t/p/original/oNOJoW2XoH3shkQxHtOyacJRBCQ.jpg', 'It took a lot of cajoling to get Bob, a recently widowed architect, to go on a blind date at a quirky Irish-Italian eatery. Once there, he''s smitten instantly not with his date but with the sharp-witted waitress. Everything seems to be going great until an unbelievable truth is revealed, one that could easily break both of their hearts for good.', NULL, NULL, 1.5829, 6.672, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
