INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3934, 27850, 'tt0173886', NULL, 'Halloweentown', 'Halloweentown', 'movie', 1998, 'https://image.tmdb.org/t/p/w500/y9RJCxJMbWqhXjkBgC0VXETmHj6.jpg', 'https://image.tmdb.org/t/p/original/dOaF7zNAHYsSaAp8PXrUt4qfm8k.jpg', 'On her 13th birthday, Marnie learns she''s a witch, discovers a secret portal, and is transported to Halloweentown — a magical place where ghosts and ghouls, witches and werewolves live apart from the human world. But she soon finds herself battling wicked warlocks, evil curses, and endless surprises.', NULL, NULL, 0.8289, 6.818, 0, 7.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
