INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3937, 449176, 'tt5164432', NULL, 'Love, Simon', 'Love, Simon', 'movie', 2018, 'https://image.tmdb.org/t/p/w500/snIsqVPmlu4LPjvToHpDotxa7Eh.jpg', 'https://image.tmdb.org/t/p/original/nJSPkq5dtASykhiYIZhpCX9Zgeq.jpg', 'Everyone deserves a great love story, but for 17-year-old Simon Spier, it''s a little more complicated. He hasn''t told his family or friends that he''s gay, and he doesn''t know the identity of the anonymous classmate that he''s fallen for online.', NULL, NULL, 5.5898, 7.97, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
