INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3940, 15785, 'tt0092746', NULL, 'Cherry 2000', 'Cherry 2000', 'movie', 1987, 'https://image.tmdb.org/t/p/w500/t3uds00MHLsibhKLCL0BbCEGxXb.jpg', 'https://image.tmdb.org/t/p/original/vjlBasTA8imogIxQLHzsUrCMjJB.jpg', 'When successful businessman Sam Treadwell finds that his android wife, Cherry model 2000 has blown a fuse, he hires sexy renegade tracker E. Johnson to find her exact duplicate. But as their journey to replace his perfect mate leads them into the treacherous and lawless region of ''The Zone'', Treadwell learns the hard way that the perfect woman is made not of computer chips and diodes.', NULL, NULL, 0.7437, 5.975, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3941, 25763, 'tt0075909', NULL, 'Damnation Alley', 'Damnation Alley', 'movie', 1977, 'https://image.tmdb.org/t/p/w500/le6eG9xm7xmDWvnQIRK7prH5U69.jpg', 'https://image.tmdb.org/t/p/original/eMMDskrOnepuahAilFZ1hKhkDXM.jpg', 'Following World War III, four survivors at a desert military installation attempt to drive across the desolate wasteland of America to Albany, where they hope more survivors are living, using a specially built vehicles to protect themselves against the freakish weather, mutated plant and animal life, and other dangers encountered along the way.', NULL, NULL, 1.3666, 5.148, 0, 2.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3942, 10061, 'tt0116225', NULL, 'Escape from L.A.', 'Escape from L.A.', 'movie', 1996, 'https://image.tmdb.org/t/p/w500/3L9lL2eUsmLNNfENPwNOc82Hzpw.jpg', 'https://image.tmdb.org/t/p/original/wzC2p07FfCsOTLo2aUeGBUQhsHX.jpg', 'Into the 9.6-quaked Los Angeles of 2013 comes Snake Plissken. His job: wade through L.A.''s ruined landmarks to retrieve a doomsday device.', NULL, NULL, 2.8121, 5.9, 0, 7.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3943, 98, 'tt0172495', NULL, 'Gladiator', 'Gladiator', 'movie', 2000, 'https://image.tmdb.org/t/p/w500/wN2xWp1eIwCKOD0BHTcErTBv1Uq.jpg', 'https://image.tmdb.org/t/p/original/jhk6D8pim3yaByu1801kMoxXFaX.jpg', 'After the death of Emperor Marcus Aurelius, his devious son takes power and demotes Maximus, one of Rome''s most capable generals who Marcus preferred. Eventually, Maximus is forced to become a gladiator and battle to the death against other men for the amusement of paying audiences.', NULL, NULL, 12.5917, 8.229, 0, 2.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3944, 16869, 'tt0361748', NULL, 'Inglourious Basterds', 'Inglourious Basterds', 'movie', 2009, 'https://image.tmdb.org/t/p/w500/aupnPtagH9JVBuMrGEanf4iqXEQ.jpg', 'https://image.tmdb.org/t/p/original/hwNtEmmugU5Yd7hpfprNWI0DGIn.jpg', 'In Nazi-occupied France during World War II, a group of Jewish-American soldiers known as "The Basterds" are chosen specifically to spread fear throughout the Third Reich by scalping and brutally killing Nazis. The Basterds, lead by Lt. Aldo Raine soon cross paths with a French-Jewish teenage girl who runs a movie theater in Paris which is targeted by the soldiers.', NULL, NULL, 15.4998, 8.217, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3945, 8810, 'tt0082694', NULL, 'Mad Max 2', 'Mad Max 2', 'movie', 1981, 'https://image.tmdb.org/t/p/w500/l1KVEhkGDpWRzQ0VqIhZqDDuOim.jpg', 'https://image.tmdb.org/t/p/original/MMSI9WzRmOdqXarevQ3Kqnytrx.jpg', 'Max Rockatansky returns as the heroic loner who drives the dusty roads of a postapocalyptic Australian Outback in an unending search for gasoline. Arrayed against him and the other scraggly defendants of a fuel-depot encampment are the bizarre warriors commanded by the charismatic Lord Humungus, a violent leader whose scruples are as barren as the surrounding landscape.', NULL, NULL, 5.8605, 7.4, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3946, 795778, 'tt9568230', NULL, 'Night Raiders', 'Night Raiders', 'movie', 2021, 'https://image.tmdb.org/t/p/w500/wCjGxpp6jGtaef0PNGy66Vdoco0.jpg', 'https://image.tmdb.org/t/p/original/tTcDNgjfDFMJJyc5wJUPMuUpkkk.jpg', 'The year is 2043. A military occupation controls disenfranchised cities in post-war North America. Children are property of the State. A desperate Cree woman joins an underground band of vigilantes to infiltrate a State children’s academy and get her daughter back. Night Raiders is a female-driven dystopian drama about resilience, courage and love.', NULL, NULL, 0.847, 4.8, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3947, 523638, 'tt6372694', NULL, 'Prisoners of the Ghostland', 'Prisoners of the Ghostland', 'movie', 2021, 'https://image.tmdb.org/t/p/w500/j5HRzcvN1QXZLvwfc3NLxX8XQJY.jpg', 'https://image.tmdb.org/t/p/original/pXn6x9SILzNT0ECPz87iEwyybA9.jpg', 'In the treacherous frontier city of Samurai Town, a ruthless bank robber is sprung from jail by wealthy warlord The Governor, whose adopted granddaughter Bernice has gone missing. The Governor offers the prisoner his freedom in exchange for retrieving the runaway. Strapped into a leather suit that will self-destruct within five days, the bandit sets off on a journey to find the young woman—and his own path to redemption.', NULL, NULL, 1.2028, 4.982, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3948, 47342, 'tt0091818', NULL, 'Radioactive Dreams', 'Radioactive Dreams', 'movie', 1986, 'https://image.tmdb.org/t/p/w500/8eUEbWEpeE9xQ4ywv3Opos0atQw.jpg', 'https://image.tmdb.org/t/p/original/A76sKlrRcAHhQ3OtKPMBcR9psFx.jpg', 'After an atomic war Phillip Hammer and Marlowe Chandler have spent 15 years on their own in an bunker, stuffed with junk from the 40s and old detective novels. Now, 19 years old, they leave their shelter to find a world full of mutants, freaks and cannibals. They become famous detectives in the struggle for the two keys that could fire the last nuclear weapon.', NULL, NULL, 0.4552, 5.4, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3949, 316154, 'tt4334266', NULL, 'The Bad Batch', 'The Bad Batch', 'movie', 2017, 'https://image.tmdb.org/t/p/w500/7o14VaMphEIzPwzeW6FP3A6zb4W.jpg', 'https://image.tmdb.org/t/p/original/aQ06MnEDLh9X3ZOtY21UD2XB197.jpg', 'After being exiled to a fenced-off wasteland, Arlen is kidnapped by a group of cannibals and goes on a journey to reunite a missing girl with her father.', NULL, NULL, 1.6029, 5.275, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3950, 11362, 'tt0245844', NULL, 'The Count of Monte Cristo', 'The Count of Monte Cristo', 'movie', 2002, 'https://image.tmdb.org/t/p/w500/ifMgDAUXVQLY4DeOu3VTTi55jSP.jpg', 'https://image.tmdb.org/t/p/original/AmN8ozRE0AbMGgZhqBu4fUjZkRt.jpg', 'Young sailor Edmond Dantès is wrongfully imprisoned, escapes, finds treasure, and reinvents himself as the wealthy Count of Monte Cristo to exact revenge on those who betrayed him.', NULL, NULL, 3.8984, 7.68, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3951, 429, 'tt0060196', NULL, 'The Good, the Bad and the Ugly', 'Il buono, il brutto, il cattivo', 'movie', 1966, 'https://image.tmdb.org/t/p/w500/bX2xnavhMYjWDoZp1VM6VnU1xwe.jpg', 'https://image.tmdb.org/t/p/original/Adrip2Jqzw56KeuV2nAxucKMNXA.jpg', 'While the Civil War rages on between the Union and the Confederacy, three men – a quiet loner, a ruthless hitman, and a Mexican bandit – comb the American Southwest in search of a strongbox containing $200,000 in stolen gold.', NULL, NULL, 10.0033, 8.466, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3952, 15067, 'tt0901487', NULL, 'The Good, the Bad, the Weird', '좋은 놈, 나쁜 놈, 이상한 놈', 'movie', 2008, 'https://image.tmdb.org/t/p/w500/lbPZ0aNoF0cHisg6DubFO2eS8so.jpg', 'https://image.tmdb.org/t/p/original/gec3e76TRGUBx1Ut0c6yuSahVDp.jpg', 'The story of three Korean outlaws in 1930s Manchuria and their dealings with the Japanese army and Chinese and Russian bandits. The Good (a bounty hunter), the Bad (a hitman), and the Weird (a thief) battle the army and the bandits in a race to use a treasure map to uncover the riches of legend.', NULL, NULL, 1.4804, 7.163, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3953, 21512, 'tt0094764', NULL, 'The Blood of Heroes', 'The Blood of Heroes', 'movie', 1989, 'https://image.tmdb.org/t/p/w500/ykdEyq2GCKRr8TsUBuVkRWuWkLj.jpg', 'https://image.tmdb.org/t/p/original/4SHACXdVAxg464kuRuqxurDAUl5.jpg', 'Set in a futuristic world where the only sport that has survived in a wasted society is the brutal game known as jugging. Sallow, the leader of a rag-tag team, has played in the main Leagues before, but was cast out because of indiscretions with a lady. Now joined by a talented newcomer, Kidda, an ambitious young peasant girl, he and his team find they have one last chance for glory.', NULL, NULL, 1.4539, 5.9, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3954, 46528, 'tt1032751', NULL, 'The Warrior''s Way', 'The Warrior''s Way', 'movie', 2010, 'https://image.tmdb.org/t/p/w500/otjBqNDpZ3C9mzfDOI4kaiib3Qd.jpg', 'https://image.tmdb.org/t/p/original/6FhmSHAmSjm5FGpLe2xqAl7ekFP.jpg', 'A warrior-assassin is forced to hide in a small town in the American Badlands after refusing a mission.', NULL, NULL, 1.7513, 6.616, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3955, 133748, 'tt14261112', NULL, 'Twisted Metal', 'Twisted Metal', 'tv', 2023, 'https://image.tmdb.org/t/p/w500/zMwMClR9y7RBeVWMEmNn8LwUJHz.jpg', 'https://image.tmdb.org/t/p/original/6wLJiFwmuZNvTiE9aqFqx4dDcWh.jpg', 'A motor-mouthed outsider with no memory of his past is offered a chance at a better life, but only if he can successfully deliver a mysterious package across a post-apocalyptic wasteland. With the help of a badass axe-wielding car thief, he’ll face savage marauders driving vehicles of destruction and other dangers of the open road, including a deranged clown who drives an all too familiar ice cream truck.', NULL, NULL, 6.0334, 7.713, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3956, 155131, 'tt0104559', NULL, 'The Legend of Zipang', 'ZIPANG', 'movie', 1990, 'https://image.tmdb.org/t/p/w500/1VjtL65sR8MXzSRSJbV6Ej1kU3x.jpg', 'https://image.tmdb.org/t/p/original/bvWWO8KDpWpcT0qXdGhta1XxF7j.jpg', 'Jigoku Gokurakumaru is a samurai on the run. One bounty hunter hoping to collect the sizeable reward is Teppo Oyuri, a comely lass who is an ace shot with her pearl-laden pistol. Before she can set her sights on Gokurakumaru, he is attacked by a hoard of sword-wielding thugs also hoping to collect the reward. He dispatches them with bloody aplomb. Later, Gokurakumaru and Oyuri -- who has fallen for the master swordsman in spite of herself -- venture to Zipang, the Land of Gold, in search of a magical gold sword.', NULL, NULL, 0.6322, 5.833, 0, 9.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3957, 449913, 'tt6849036', NULL, 'The Eternals', 'Les éternels', 'movie', 2017, 'https://image.tmdb.org/t/p/w500/wklAFv3bO6E2vXeQl7kzXCiz63V.jpg', 'https://image.tmdb.org/t/p/original/jIfPLloXelmSr9aBH0So50N5hww.jpg', 'Human beings who have experienced such a strong shock that they are no longer even afraid of death (as it often happens to genocide survivors) sometimes fall into what is known as a feeling of timelessness or a “melancholy”. They live somewhat “outside” time, a mode of extra-temporal existence, waiting for the day on which they will be freed from their suffering. It is the people — almost ghosts having survived the conflict in Nagorno-Karabakh between Armenians and Azerbaijani that has lasted for almost twenty years — that the filmmaker shows and listens to in his film. Behind them, behind their wandering bodies, behind their frenzies, is what remains of the collapse of the Soviet Union in Caucasus: ruins, uninhabited spaces, tombs, vestiges of war, trenches where soldiers watch for an invisible enemy.', NULL, NULL, 0.5412, 3.5, 0, 7.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3958, 837335, 'tt14561712', NULL, 'La Chimera', 'La chimera', 'movie', 2023, 'https://image.tmdb.org/t/p/w500/dV6SYHmmFLXQU7oKRfK4pOFCX6M.jpg', 'https://image.tmdb.org/t/p/original/ovtTn2GkzOYsMvAVWl6Bt0jN4Ye.jpg', 'Everyone has their own Chimera, something they try to achieve but never manage to find. For Arthur, the Chimera looks like the woman he lost, Beniamina. In an adventurous journey between the living and the dead, between forests and cities, between celebrations and solitudes, the intertwined destinies of these characters unfold, all in search of the Chimera.', NULL, NULL, 1.7787, 7.293, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3959, 426426, 'tt6155172', NULL, 'Roma', 'Roma', 'movie', 2018, 'https://image.tmdb.org/t/p/w500/dtIIyQyALk57ko5bjac7hi01YQ.jpg', 'https://image.tmdb.org/t/p/original/zl9uqCl5iUSb50sTk2BPzw6bJnU.jpg', 'In 1970s Mexico City, two domestic workers help a mother of four while her husband is away for an extended period of time.', NULL, NULL, 3.2098, 7.618, 0, 12.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3960, 11779, 'tt0186508', NULL, 'Buena Vista Social Club', 'Buena Vista Social Club', 'movie', 1999, 'https://image.tmdb.org/t/p/w500/b8psTDXSelHiab1I7L8rFdYs0IC.jpg', 'https://image.tmdb.org/t/p/original/y5Y12Pds6Z4ipLg482Azhp4xb9x.jpg', 'In this fascinating Oscar-nominated documentary, American guitarist Ry Cooder brings together a group of legendary Cuban folk musicians (some in their 90s) to record a Grammy-winning CD in their native city of Havana. The result is a spectacular compilation of concert footage from the group''s gigs in Amsterdam and New York City''s famed Carnegie Hall, with director Wim Wenders capturing not only the music -- but also the musicians'' life stories.', NULL, NULL, 0.3894, 7.5, 0, 15.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3961, 1220564, 'tt27847051', NULL, 'The Secret Agent', 'O Agente Secreto', 'movie', 2025, 'https://image.tmdb.org/t/p/w500/iLE2YOmeboeTDC7GlOp1dzh1VFo.jpg', 'https://image.tmdb.org/t/p/original/eeGRpU64sIrRApjWXvTpK5Lep2K.jpg', 'Brazil, 1977. Marcelo, a technology expert in his early 40s, is on the run. Hoping to reunite with his son, he travels to Recife during Carnival but soon realizes that the city is not the safe haven he was expecting.', NULL, NULL, 6.5718, 7.214, 0, 12.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3962, 980296, 'tt15744108', NULL, 'Los Frikis', 'Los Frikis', 'movie', 2024, 'https://image.tmdb.org/t/p/w500/kCGWNd8yFQ3E695kYuaUUv62pJP.jpg', 'https://image.tmdb.org/t/p/original/fOGTvPtALsehlUFYUoZPUoRIHhd.jpg', 'Gustavo idolizes his older brother Paco and his punk, "Frikis" bandmates. When word reaches the Frikis of a potential reprieve from the effects of the economic crisis, they do the now unthinkable: deliberately inject themselves with HIV to live at a government-run treatment home. It''s there that they create their own utopia to live and play music freely.', NULL, NULL, 0.6472, 6.147, 0, 12.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3963, 38985, 'tt0076740', NULL, 'Sorcerer', 'Sorcerer', 'movie', 1977, 'https://image.tmdb.org/t/p/w500/2b7oexm173SF1FSEq0DdgxZZNRH.jpg', 'https://image.tmdb.org/t/p/original/g7prwSflNODkHZI6792MYoU4qoh.jpg', 'Four men from different parts of the globe, all hiding from their pasts in the same remote South American town, agree to risk their lives transporting several cases of dynamite (which is so old that it is dripping unstable nitroglycerin) across dangerous jungle terrain.', NULL, NULL, 1.9982, 7.5, 0, 12.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3964, 5001, 'tt0247196', NULL, 'Before Night Falls', 'Before Night Falls', 'movie', 2000, 'https://image.tmdb.org/t/p/w500/kb2dqj73cfmt6qHAh1ySIlVm6v0.jpg', 'https://image.tmdb.org/t/p/original/jnJ4i6vPQETcfjxOvAODxzsdQfX.jpg', 'Spanning several decades, this powerful biopic offers a glimpse into the life of famed Cuban poet and novelist Reinaldo Arenas, an artist who was vilified for his homosexuality in Fidel Castro''s Cuba.', NULL, NULL, 0.7861, 6.661, 0, 13.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3965, 1360, 'tt0120679', NULL, 'Frida', 'Frida', 'movie', 2002, 'https://image.tmdb.org/t/p/w500/a4hgR6aKoohB6MHni171jbi9BkU.jpg', 'https://image.tmdb.org/t/p/original/gcGaSXzmodu53ABb0wOWrVWjKeg.jpg', 'A biography of artist Frida Kahlo, who channeled the pain of a crippling injury and her tempestuous marriage into her work.', NULL, NULL, 2.0066, 7.384, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3966, 868, 'tt0468565', NULL, 'Tsotsi', 'Tsotsi', 'movie', 2005, 'https://image.tmdb.org/t/p/w500/r3ebTJFcDZ35GaKcuUQQe243z4f.jpg', 'https://image.tmdb.org/t/p/original/gLxgqHpJcMvB6cMTA4hUBxoOMJ1.jpg', 'A young South African boy from the Johannesburg ghetto named Tsotsi, meaning Gangster, leaves home as a child to get away from his helpless parents. Now a teenage thug, Tsotsi finds a baby in the back seat of a car he''s just stolen. He decides that it is his responsibility to care for the infant and in the process learns that maybe the criminal life isn’t the best way.', NULL, NULL, 0.703, 6.935, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3967, 55, 'tt0245712', NULL, 'Amores Perros', 'Amores perros', 'movie', 2000, 'https://image.tmdb.org/t/p/w500/A4lH22nlFF7MdalGfcvSrlC1ttt.jpg', 'https://image.tmdb.org/t/p/original/tJTRLtdKPeVT8HORSbeHpdb8BKg.jpg', 'A fatalistic car crash in Mexico city sets off a chain of events in the lives of three people: a supermodel, a young man wanting to run off with his sister-in-law, and a homeless man.', NULL, NULL, 3.9043, 7.642, 0, 13.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3968, 17295, 'tt0058946', NULL, 'The Battle of Algiers', 'La battaglia di Algeri', 'movie', 1966, 'https://image.tmdb.org/t/p/w500/2p3AFtOHFvP6OeVMqlnL1zLKOqL.jpg', 'https://image.tmdb.org/t/p/original/ze7GsNSv418o7pzqc9fb00LWWDk.jpg', 'Paratrooper commander Colonel Mathieu, a former French Resistance fighter during World War II, is sent to Algeria to reinforce efforts to squelch the uprisings of the Algerian War. There he faces Ali la Pointe, a former petty criminal who, as the leader of the Algerian Front de Liberation Nationale, directs terror strategies against the colonial French government occupation. As each side resorts to ever-increasing brutality, no violent act is too unthinkable.', NULL, NULL, 1.5807, 7.893, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3969, 1107440, 'tt36514797', NULL, 'To the West, in Zapata', 'Al oeste, en Zapata', 'movie', 2025, 'https://image.tmdb.org/t/p/w500/tSscjA8wpJGhrEwAmAJOrFbHkux.jpg', 'https://image.tmdb.org/t/p/original/caddV4Ok0bzUmwRw0W3NhNDWDa6.jpg', 'Landi and Mercedes live in Cuba’s Zapata swamp, a biosphere reserve. To feed their sick child, Landi must secretly hunt crocodiles, leaving his wife and son behind for days on end.', NULL, NULL, 0.2137, 8.0, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3970, 8053, 'tt0419294', NULL, 'The Three Burials of Melquiades Estrada', 'The Three Burials of Melquiades Estrada', 'movie', 2005, 'https://image.tmdb.org/t/p/w500/uHOEb6mo45qMSJaZqbkVa7oW1Y7.jpg', 'https://image.tmdb.org/t/p/original/3n4Bfg390okuusER56enINib0kL.jpg', 'When brash Texas border officer Mike Norton wrongfully kills and buries the friend and ranch hand of Pete Perkins, the latter is reminded of a promise he made to bury his friend, Melquiades Estrada, in his Mexican home town. He kidnaps Norton and exhumes Estrada''s corpse, and the odd caravan sets out on horseback for Mexico.', NULL, NULL, 1.0841, 7.023, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3971, 42148, 'tt0082912', NULL, 'Pixote', 'Pixote: A Lei do Mais Fraco', 'movie', 1980, 'https://image.tmdb.org/t/p/w500/zaBtclnYKv2JkgRDQ7OiFtWHm4e.jpg', 'https://image.tmdb.org/t/p/original/88SnnUEY4CmUJTjzhqYfY3zffEC.jpg', '10-year-old Pixote endures torture, degradation, and corruption at a local youth detention center where two of its members are murdered by policemen who frame Lilica, a 17-year-old trans hustler. Pixote helps Lilica and three other boys escape and they start to make their living by a life of crime which only escalates to more violence and death.', NULL, NULL, 0.7556, 7.937, 0, 12.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3972, 12527, 'tt0106966', NULL, 'Strawberry and Chocolate', 'Fresa y chocolate', 'movie', 1993, 'https://image.tmdb.org/t/p/w500/8riS2hGneWg78MHuhP7NqvLERRy.jpg', 'https://image.tmdb.org/t/p/original/kTlrvY35ldGN0yReCu59DfQdlcp.jpg', 'In 1979 Cuba, flamboyant gay artist Diego attempts to seduce  straitlaced David, an idealistic young communist, and fails dismally. But David conspires to be "friends" with Diego so he can monitor the artist''s subversive life for the state. As Diego and David discuss politics, individuality and personal expression in Castro''s Cuba, a genuine friendship develops between the two.', NULL, NULL, 1.7265, 7.0, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
