INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3975, 21253, 'tt0119815', NULL, 'Four Days in September', 'O Que é Isso, Companheiro?', 'movie', 1997, 'https://image.tmdb.org/t/p/w500/lwrkDaM1sbxV83tjRT59LyCHcbI.jpg', 'https://image.tmdb.org/t/p/original/mqFaz5jlBNHwCNRxNzLPXLS2vgR.jpg', 'Fernando, a journalist, and his friend César join terrorist group MR8 in order to fight Brazilian dictatorial regime during the late sixties. César, however, is wounded and captured during a bank hold up. Fernando then decides to kidnap the American ambassador in Brazil and ask for the release of fifteen political prisoners in exchange for his life.', NULL, NULL, 0.717, 7.5, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
