INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4046, 6552, 'tt0138510', NULL, 'Idle Hands', 'Idle Hands', 'movie', 1999, 'https://image.tmdb.org/t/p/w500/mCO4gU1lkViGXTkoRBEYrvjDIJu.jpg', 'https://image.tmdb.org/t/p/original/vSX4JjjifAUnF4PD5J9czE4Fz0C.jpg', 'Anton is a cheerful but exceedingly non-ambitious 17-year-old stoner who lives to stay buzzed, watch TV, and moon over Molly, the beautiful girl who lives next door. However, it turns out that the old cliché about idle hands being the devil''s playground has a kernel of truth after all.', NULL, NULL, 2.2501, 6.215, 0, 2.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4047, 6951, 'tt0098536', NULL, 'Turner & Hooch', 'Turner & Hooch', 'movie', 1989, 'https://image.tmdb.org/t/p/w500/nllMNbjgvUpw378czm5vBYzZqg1.jpg', 'https://image.tmdb.org/t/p/original/yGCAyKBiHIuM9IdqjxhJ1BhbAgV.jpg', 'Detective Scott Turner has three days left in the local police department before he moves to a bigger city to get some ''real'' cases—not just misdemeanors. When Amos Reed is murdered, Scott sets himself on the case, but the closest thing to a witness to the murder is Reed''s dog, Hooch, which Scott has to take care of—to avoid Hooch being ''put to sleep''.', NULL, NULL, 1.3388, 6.327, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4048, 61664, 'tt2431438', NULL, 'Sense8', 'Sense8', 'tv', 2015, 'https://image.tmdb.org/t/p/w500/kmyvlQ9QKzgdZY31rXaUlgCnzrB.jpg', 'https://image.tmdb.org/t/p/original/3G0oM3TvwOGJRRiiYDnTAoMXiaN.jpg', 'One gunshot, one death, one moment out of time that irrevocably links eight minds in disparate parts of the world, putting them in each other''s lives, each other''s secrets, and in terrible danger. Ordinary people suddenly reborn as "Sensates."', NULL, NULL, 10.2815, 7.727, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4049, 194188, 'tt2836166', NULL, 'Punk''s Dead: SLC Punk 2', 'Punk''s Dead: SLC Punk 2', 'movie', 2016, 'https://image.tmdb.org/t/p/w500/AptQQxD4HMNMZZQuVD1XKojCJiZ.jpg', 'https://image.tmdb.org/t/p/original/eaadGOWEwKa0nIK6QaP3s1jpYvR.jpg', 'Punk''s Dead, the sequel to 1999 cult hit SLC Punk, is a punk romp through the Utah hinterlands. Ross, Penny and Crash, young outsiders from different tribes, embark on a road trip to a huge punk show. Ross, 19, is the love child of Trish and Heroin Bob, who died before Ross was born. During their odyssey, and with the help of a healthy dose of drugs, alcohol and punk music, Ross shreds his darkly Gothic outlook and embraces life. His mother Trish, who raised Ross alone in her steam punk shop, discovers that he is in a crisis. She recruits his ''uncles,'' Bob''s old SLC gang, to help find him. When all collide at the concert, they are forced to deal with their unresolved relationships with Bob.', NULL, NULL, 0.7192, 4.5, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4050, 11531, 'tt0229260', NULL, 'Book of Shadows: Blair Witch 2', 'Book of Shadows: Blair Witch 2', 'movie', 2000, 'https://image.tmdb.org/t/p/w500/l1jF93S9FYbzp3Byh5VUA1KApSJ.jpg', 'https://image.tmdb.org/t/p/original/unVjWj6KsRXk67pEkBfxflpbyRV.jpg', 'A group of college students decide to take part in a witch hunt tour inspired by a horror movie. As the adventure goes awry, the students realise that an evil being has followed them home.', NULL, NULL, 1.2242, 4.358, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4051, 91549, 'tt1407065', NULL, 'The Moth Diaries', 'The Moth Diaries', 'movie', 2011, 'https://image.tmdb.org/t/p/w500/oVoUBnhef1EPTcg7gIOoDUI3Rhu.jpg', 'https://image.tmdb.org/t/p/original/v9H1i8oN2c9PPn51MTjdEEi9QSc.jpg', 'Rebecca is a young girl who, haunted by her father’s suicide, enrolls in an elite boarding school for girls. Before long, her friendship with the popular Lucy is shattered by the arrival of a dark and mysterious new student named Ernessa, whom Rebecca suspects may be responsible for the rising body count at the school.', NULL, NULL, 0.9894, 5.3, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4052, 8067, 'tt0119535', NULL, 'A Life Less Ordinary', 'A Life Less Ordinary', 'movie', 1997, 'https://image.tmdb.org/t/p/w500/tk7WNEwLZepFU2yPIIkRuQOO0Q9.jpg', 'https://image.tmdb.org/t/p/original/78fqm4OGHe4a1Sl1WhX12pV8Ocr.jpg', 'A couple of angels, O''Reilly and Jackson, are sent to Earth to make sure that their next supervised love-connection succeeds. They follow Celine, a spoiled rich girl who has just accidentally shot a suitor and, due to a misunderstanding, is kidnapped by janitor Robert. Although Celine quickly frees herself, she stays with Robert for thrills. O''Reilly and Jackson pursue, hoping to unite the prospective lovers.', NULL, NULL, 1.1853, 6.154, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4053, 7984, 'tt0107207', NULL, 'In the Name of the Father', 'In the Name of the Father', 'movie', 1993, 'https://image.tmdb.org/t/p/w500/3NcIkKxaO2SmRVsG1v50XhtmL0f.jpg', 'https://image.tmdb.org/t/p/original/1GZVHgJUcVyytQRJ533GpMavAcL.jpg', 'A small-time Belfast thief, Gerry Conlon, is wrongly convicted of an IRA bombing in London, along with his father and friends, and spends 15 years in prison fighting to prove his innocence.', NULL, NULL, 2.308, 7.888, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4054, 500, 'tt0105236', NULL, 'Reservoir Dogs', 'Reservoir Dogs', 'movie', 1992, 'https://image.tmdb.org/t/p/w500/xi8Iu6qyTfyZVDVy60raIOYJJmk.jpg', 'https://image.tmdb.org/t/p/original/jwt159hXWA9Q5xpBo8hWb3zwLi7.jpg', 'A botched robbery indicates a police informant, and the pressure mounts in the aftermath at a warehouse. Crime begets violence as the survivors -- veteran Mr. White, newcomer Mr. Orange, psychopathic parolee Mr. Blonde, bickering weasel Mr. Pink and Nice Guy Eddie -- unravel.', NULL, NULL, 5.8612, 8.112, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4055, 12498, 'tt0117666', NULL, 'Sling Blade', 'Sling Blade', 'movie', 1996, 'https://image.tmdb.org/t/p/w500/rioWUWXPFNSjwm9NO2aau9x0wlP.jpg', 'https://image.tmdb.org/t/p/original/s0MYaSiEZy9H0cXxxay5LEdcxYs.jpg', 'Karl Childers, a mentally disabled man, has been in the custody of the state mental hospital since the age of 12 for killing his mother and her lover. Although thoroughly institutionalized, he is deemed fit to be released into the outside world.', NULL, NULL, 0.9456, 7.537, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4056, 11830, 'tt0092048', NULL, 'Tampopo', 'タンポポ', 'movie', 1985, 'https://image.tmdb.org/t/p/w500/ArYdSuX3zY9fMsE4LqmBl7xJq5R.jpg', 'https://image.tmdb.org/t/p/original/oq8HM9TOSbH54Xy0OBJGzYrtUC7.jpg', 'In this humorous paean to the joys of food, a pair of truck drivers happen onto a decrepit roadside shop selling ramen noodles. The widowed owner, Tampopo, begs them to help her turn her establishment into a paragon of the "art of noodle-soup making". Interspersed are satirical vignettes about the importance of food to different aspects of human life.', NULL, NULL, 1.6547, 7.783, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4057, 1212763, 'tt31170389', NULL, 'Evil Dead Burn', 'Evil Dead Burn', 'movie', 2026, 'https://image.tmdb.org/t/p/w500/ztadKzIIR0ERYqpHteaPFtk7inP.jpg', 'https://image.tmdb.org/t/p/original/A5Tz6ogGt4VV8NESG9oWVct5bo1.jpg', 'After her husband''s abrupt death, Alice seeks solace with his remaining family — descendants of a leading researcher on demonic possession. As her in-laws transform one by one into creatures that feed on fear, she comes to discover that the vows she took in life survive even in death.', NULL, NULL, 72.3815, 6.8, 0, 12.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4058, 13256, 'tt0490181', NULL, 'Mutant Chronicles', 'Mutant Chronicles', 'movie', 2008, 'https://image.tmdb.org/t/p/w500/vHH9VnQZYdhWE9PMMKUpYrG1Z0Z.jpg', 'https://image.tmdb.org/t/p/original/6gFKEYJ3UugiIm6JUGcoaEDah9M.jpg', 'It''s the year 2707. Earth''s natural resources have all but been exhausted by mankind. Battles rage for the remainder between the competing Corporations. During one such battle the seal is broken and awakens an ancient and deadly machine that was once defeated thousands of years ago. The order that awaited its return must now lead a small group of soldiers to destroy it once and for all.', NULL, NULL, 1.5274, 5.317, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4059, 19898, 'tt1188729', NULL, 'Pandorum', 'Pandorum', 'movie', 2009, 'https://image.tmdb.org/t/p/w500/mNMfa6r3pl0EzFIKEkVcxyr6Rc7.jpg', 'https://image.tmdb.org/t/p/original/2M5V8VcK02o4R5cxe7Ew1ltaxKr.jpg', 'Two crew members wake up on an abandoned spacecraft with no idea who they are, how long they''ve been asleep, or what their mission is. The two soon discover they''re actually not alone – and the reality of their situation is more horrifying than they could have imagined.', NULL, NULL, 1.8858, 6.595, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4060, 261579, 'tt33204697', NULL, 'Secret Level', 'Secret Level', 'tv', 2024, 'https://image.tmdb.org/t/p/w500/856MRq23grNxpeVl1PdFgmmLiT0.jpg', 'https://image.tmdb.org/t/p/original/5AvZxT1BtPyP9ua1SjcUyWUMIiz.jpg', 'Adult animated series of original short stories which are set within the worlds of beloved video games. Each episode serves as a gateway to a new adventure, unlocking exciting worlds from beloved gaming classics and highly anticipated new titles.', NULL, NULL, 10.5765, 7.413, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4061, 26198, 'tt0085780', NULL, 'The Keep', 'The Keep', 'movie', 1983, 'https://image.tmdb.org/t/p/w500/yd9wU3oajNxwaFHQ02rtTBuSFJD.jpg', 'https://image.tmdb.org/t/p/original/iQYwVxXDSBMfZB4JTW5LRi7sBZR.jpg', 'Set during World War II, a German army garrison is sent to guard a mountain pass in a village in Romania''s Carpathian mountains and sets up barracks in an ancient stone fortress. Two of the soldiers unwittingly release a mysterious entity that kills or corrupts those within its influence, drawing the attention of a Gestapo commander, a Jewish scholar, and a mysterious traveller.', NULL, NULL, 1.2235, 5.643, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4062, 4923, 'tt0070948', NULL, 'Zardoz', 'Zardoz', 'movie', 1974, 'https://image.tmdb.org/t/p/w500/6qvQhJhvM7wWPB2LjVpivSNraIv.jpg', 'https://image.tmdb.org/t/p/original/tFvyHuyeYWsUUcSA8kfg4aQYxX9.jpg', 'In the far future, a savage trained only to kill finds a way into the community of bored immortals that alone preserves humanity''s achievements.', NULL, NULL, 1.138, 5.936, 0, 8.6, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4063, 25628, 'tt0080846', NULL, 'Hawk the Slayer', 'Hawk the Slayer', 'movie', 1980, 'https://image.tmdb.org/t/p/w500/rOuvXCzJoyR8eJnmArF5CtbLkN5.jpg', 'https://image.tmdb.org/t/p/original/AjH5DOvTgwFp55qmg4Sa7tvGOE8.jpg', 'Hawk the Slayer, after seeing both his father and bride die at the hands of his malevolent brother, Voltan, sets out for revenge and the chance to live up to his title. Tooling himself up with the "mind-sword" and recruiting a motley band of warriors — a giant, a dwarf, a one-armed man with a machine-crossbow, and an elf with the fastest bow in the land — Hawk leads the battle against Voltan to free the land from the forces of evil and avenge his loved ones.', NULL, NULL, 0.4177, 4.8, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4064, 22501, 'tt0084315', NULL, 'Time Masters', 'Les maîtres du temps', 'movie', 1982, 'https://image.tmdb.org/t/p/w500/4ktdTOrJnSk7iCtX6Q2QR0sR9Je.jpg', 'https://image.tmdb.org/t/p/original/eOgq3wNremNJ5V3hxapQop7JXvP.jpg', 'On planet Perdide, an attack of giant hornets leaves young Piel alone in a wrecked car with his dying father. A mayday message reaches their friend Jaffar, an adventurer travelling through space. Onboard Jaffar’s shuttle are the renegade Prince Matton, his fiancée, and Silbad, who knows Perdide well. Thus begins an incredible race across space to save Piel.', NULL, NULL, 1.4462, 7.2, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4065, 7348, 'tt0058530', NULL, 'Robinson Crusoe on Mars', 'Robinson Crusoe on Mars', 'movie', 1964, 'https://image.tmdb.org/t/p/w500/a3MBNEoquGKZT5UYbq9o509dzTV.jpg', 'https://image.tmdb.org/t/p/original/ay8Sl3esPX1MyuBOLjl0xI2TiXX.jpg', 'Stranded on Mars with only a monkey as a companion, an astronaut must figure out how to find oxygen, water, and food and companionship on the lifeless planet.', NULL, NULL, 0.7479, 6.3, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4066, 52302, 'tt0057295', NULL, 'Matango', 'マタンゴ', 'movie', 1963, 'https://image.tmdb.org/t/p/w500/kfUJ1XO15yWz6U2N7vmubJS9aX8.jpg', 'https://image.tmdb.org/t/p/original/7Mmp2I9AMmOkOCSoC8jb3w81YjC.jpg', 'Five vacationers and two crewmen become stranded on a tropical island near the equator. The island has little edible food for them to use as they try to live in a fungus covered hulk while repairing Kessei''s yacht. Eventually they struggle over the food rations which were left behind by the former crew. Soon they discover something unfriendly there...', NULL, NULL, 0.9237, 6.716, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4067, 70872, 'tt0049900', NULL, 'Warning from Space', '宇宙人東京に現わる', 'movie', 1956, 'https://image.tmdb.org/t/p/w500/fxK1qXaZS7S4JtMgrKWha80UuT9.jpg', 'https://image.tmdb.org/t/p/original/7MWT2RzRUIKpQARHjC3AdNGs9O1.jpg', 'Large star-shaped aliens travel to earth in hopes of warning them about an oncoming catastrophe. To prevent panic about their appearance, one alien takes the form of a popular singer.', NULL, NULL, 0.514, 5.3, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4068, 85723, 'tt9170108', NULL, 'Raised by Wolves', 'Raised by Wolves', 'tv', 2020, 'https://image.tmdb.org/t/p/w500/mTvSVKMn2Npf6zvYNbGMJnYLtvp.jpg', 'https://image.tmdb.org/t/p/original/na2xUduK8HviOFT97TiFG2MkJmY.jpg', 'After Earth is ravaged by a great religious war, an atheistic android architect sends two of his creations, Mother and Father, to start a peaceful, godless colony on the planet Kepler-22b. Their treacherous task is jeopardized by the arrival of the Mithraic, a deeply devout religious order of surviving humans.', NULL, NULL, 4.9982, 7.508, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4069, 253, 'tt0060028', NULL, 'Star Trek', 'Star Trek', 'tv', 1966, 'https://image.tmdb.org/t/p/w500/9byecLwsbbkAqGdxcKuuTI5kEzZ.jpg', 'https://image.tmdb.org/t/p/original/ywK4VrR7vL56mDGXDLMtFypwqA8.jpg', 'Space. The Final Frontier. The U.S.S. Enterprise embarks on a five year mission to explore the galaxy. The Enterprise is under the command of Captain James T. Kirk with First Officer Mr. Spock, from the planet Vulcan. With a determined crew, the Enterprise encounters Klingons, Romulans, time paradoxes, tribbles and genetic supermen led by Khan Noonian Singh. Their mission is to explore strange new worlds, to seek new life and new civilizations, and to boldly go where no man has gone before.', NULL, NULL, 21.6555, 7.995, 0, 2.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4070, NULL, NULL, 2164, 'The Neverhood', 'The Neverhood', 'game', 1996, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2h4m.jpg', NULL, 'The game follows the adventure of a claymation character named Klaymen as he discovers his origins and his purpose in a world made entirely out of clay.', 'https://www.igdb.com/games/the-neverhood--1', '["PC (Microsoft Windows)", "PlayStation"]', NULL, NULL, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4071, 19947, 'tt0088678', NULL, 'The Adventures of Mark Twain', 'The Adventures of Mark Twain', 'movie', 1985, 'https://image.tmdb.org/t/p/w500/wUYyl69qvIZOTuRJnwK07BbYSyy.jpg', 'https://image.tmdb.org/t/p/original/oLVeYWiTEtd530oXVPABp334vJZ.jpg', 'Based on elements from the stories of Mark Twain, this feature-length Claymation fantasy follows the adventures of Tom Sawyer, Becky Thatcher and Huck Finn as they stowaway aboard the interplanetary balloon of Mark Twain. Twain, disgusted with the human race, is intent upon finding Halley''s Comet and crashing into it, achieving his "destiny." It''s up to Tom, Becky, and Huck to convince him that his judgment is wrong and that he still has much to offer humanity that might make a difference. Their efforts aren''t just charitable; if they fail, they will share Twain''s fate. Along the way, they use a magical time portal to get a detailed overview of the Twain philosophy, observing the "historical" events that inspired his works.', NULL, NULL, 0.5382, 6.797, 0, 7.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4072, 16191, 'tt0104418', NULL, 'Highway to Hell', 'Highway to Hell', 'movie', 1991, 'https://image.tmdb.org/t/p/w500/672mGX0B3LIbaBQEdWKAJpCVHO5.jpg', 'https://image.tmdb.org/t/p/original/cIfa32tuybOwKZKGca1LJxfzTKZ.jpg', 'Charlie and Rachel run away from home to get married in Las Vegas. But they get attacked by a zombie who takes Rachel with him to hell, where she will become one of Satan''s brides.', NULL, NULL, 1.2154, 5.852, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4073, 54013, 'tt0080100', NULL, 'The Visitor', 'Stridulum', 'movie', 1979, 'https://image.tmdb.org/t/p/w500/nO6pEHO2bewFPgDxxdRI2taKLir.jpg', 'https://image.tmdb.org/t/p/original/bVsGMzJ1jpJpxCzzGbXjvrd4Hcq.jpg', 'An ancient intergalactic warrior arrives on Earth to put a stop to a demonic child''s plot to reproduce Satan''s next generation of evil.', NULL, NULL, 0.7588, 5.3, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4074, 455839, 'tt4815122', NULL, 'Time Trap', 'Time Trap', 'movie', 2017, 'https://image.tmdb.org/t/p/w500/583rpyMn8UL8F2oH26Sz6WoKDDe.jpg', 'https://image.tmdb.org/t/p/original/b99d8ye8eT5k0inDHhdqINkiFrd.jpg', 'A group of students become trapped inside a mysterious cave where they discover time passes differently underground than on the surface.', NULL, NULL, 4.6089, 6.318, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4075, 83100, 'tt9458304', NULL, 'Dororo', 'どろろ', 'tv', 2019, 'https://image.tmdb.org/t/p/w500/mLSJO9lj2RMHdzHJMNMoksmwlbv.jpg', 'https://image.tmdb.org/t/p/original/lLjIOxGIVnUVBHQFCBYzo7OAMHt.jpg', 'During the Warring States period, the young thief Dororo encounters Hyakkimaru, a strange, sightless boy who wields fearsome prosthetics in place of his missing limbs. Parts of Hyakkimaru’s body were traded to a group of 12 demons by his father in exchange for power, but thanks to a kindly medicine man, Hyakkimaru survived his horrifying ordeal. Now he roams the land in search of his missing body, and together he and Dororo will fight to survive in an unforgiving, demon-plagued world.', NULL, NULL, 5.3399, 8.526, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4076, NULL, NULL, 12232, 'Weird Dreams', 'Weird Dreams', 'game', 1988, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2rv9.jpg', NULL, 'A severely ill man is on the operating table when a Daemon named Emily trapping you in your own subconscious. To escape you must find four orbs, which are trapped within a selection of esoteric mini-games set within the darkest Dali-influenced recesses of the mind.

Weird Dreams is a third-person game with action and puzzle elements. The game contains bizarre levels and unorthodox activities, including feeding a wasp cotton candy, beating up hopping totem poles with fish from the sky, and an encounter with a baked chicken in a haunted house. The game comes with a "short novel" that explains the plot in detail and serves as copy protection.', 'https://www.igdb.com/games/weird-dreams', '["Commodore C64/128/MAX", "Atari ST/STE", "PC (Microsoft Windows)", "DOS", "Amiga"]', NULL, NULL, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
