INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4080, 1330443, 'tt33400719', NULL, 'Strange Harvest', 'Strange Harvest', 'movie', 2025, 'https://image.tmdb.org/t/p/w500/fYe0FNJNy0EIb8q4JUMLbbSmCth.jpg', 'https://image.tmdb.org/t/p/original/bSWw3XXqnT0m1kZzmEdozsfUvMQ.jpg', 'Detectives are thrust into a chilling hunt for a sadistic serial killer from the past whose return marks the beginning of a new wave of grotesque, otherworldly crimes tied to a cosmic force.', NULL, NULL, 2.3993, 6.7, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4081, 5084, 'tt0071003', NULL, 'Kolchak: The Night Stalker', 'Kolchak: The Night Stalker', 'tv', 1974, 'https://image.tmdb.org/t/p/w500/lgP91rWAjgqvA7IzwG3R96sAU8K.jpg', 'https://image.tmdb.org/t/p/original/krosmh0PRUX2CezxpiPpAGJGnTd.jpg', 'Kolchak: The Night Stalker is an American television series that aired on ABC during the 1974–1975 season. It featured a fictional Chicago newspaper reporter who investigated mysterious crimes with unlikely causes, particularly those that law enforcement authorities would not follow up. These often involved the supernatural or even science fiction, including fantastic creatures.', NULL, NULL, 5.6801, 7.667, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4082, 13975, 'tt0910905', NULL, 'In the Electric Mist', 'In the Electric Mist', 'movie', 2009, 'https://image.tmdb.org/t/p/w500/gsyUJovik2t5vzPyXL5tq5VWLym.jpg', 'https://image.tmdb.org/t/p/original/tQ5TSuddADLFzFugvIW49YK2NcR.jpg', 'Lt. Dave Robicheaux, a detective in New Iberia, Louisiana, is trying to link the murder of a local hooker to New Orleans mobster Julie ''Baby Feet'' Balboni, who is co-producer of a Civil War film. When the star of the film,  Elrod Sykes, reports finding another corpse in the Atchafalaya Swamp near the movie set, Robicheaux starts another investigation, believing the corpse to be the remains of a black man whose murder he witnessed 35 years earlier.', NULL, NULL, 1.7742, 6.077, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4083, 39351, 'tt1830617', NULL, 'Grimm', 'Grimm', 'tv', 2011, 'https://image.tmdb.org/t/p/w500/iOptnt1QHi6bIHmOq6adnZTV0bU.jpg', 'https://image.tmdb.org/t/p/original/oS3nip9GGsx5A7vWp8A1cazqJlF.jpg', 'After Portland homicide detective Nick Burkhardt discovers he''s descended from an elite line of criminal profilers known as "Grimms," he increasingly finds his responsibilities as a detective at odds with his new responsibilities as a Grimm.', NULL, NULL, 52.999, 8.268, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4084, 4330, 'tt0115270', NULL, 'Millennium', 'Millennium', 'tv', 1996, 'https://image.tmdb.org/t/p/w500/vGEPm7vDTGbYNkDodLnsJyl6QIc.jpg', 'https://image.tmdb.org/t/p/original/7cmCid1B70AwhbdPpKvSVxAyqll.jpg', 'A retired FBI serial-profiler joins the mysterious Millennium Group, a team of underground ex-law enforcement experts dedicated to fighting against the ever-growing forces of evil and darkness in the world.', NULL, NULL, 8.4891, 7.714, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4085, 2697, 'tt0078682', NULL, 'Sapphire & Steel', 'Sapphire & Steel', 'tv', 1979, 'https://image.tmdb.org/t/p/w500/4MTGI5vc1FQBkSG83Jo9SO6jzLo.jpg', 'https://image.tmdb.org/t/p/original/gfTsTgm6MXn7IMFsr9kvaXGae3R.jpg', 'Sapphire & Steel is a British television science-fiction fantasy series starring David McCallum as Steel and Joanna Lumley as Sapphire. Produced by ATV, it ran from 1979 to 1982 on the ITV network. The series was created by Peter J. Hammond who conceived the programme under the working title The Time Menders, after a stay in an allegedly haunted castle. Hammond also wrote all the stories except for the fifth, which was co-written by Don Houghton and Anthony Read.

None of the stories had onscreen titles, or any official titles assigned by the writers. The Region 1 Complete Series DVD release gives the titles "Escape Through a Crack in Time", "The Railway Station", "The Creature''s Revenge", "The Man Without a Face", "Dr. McDee Must Die" and "The Trap", respectively. These titles have often been cited as having been created by science fiction magazine Time Screen.', NULL, NULL, 2.3761, 7.269, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4086, 18123, 'tt1660055', NULL, 'Scooby-Doo! Mystery Incorporated', 'Scooby-Doo! Mystery Incorporated', 'tv', 2010, 'https://image.tmdb.org/t/p/w500/mu8zU2jQfPbGO5bC6RHYrSypxUd.jpg', 'https://image.tmdb.org/t/p/original/2VvLk11UlmdHFPQkDgm4KPSjLrs.jpg', 'This incarnation of the popular cartoon series finds Scooby and the gang living in Crystal Cove, a small town with a long history of ghost sightings, monster tales and other mysteries ripe for the sleuths to solve once and for all. But the longstanding Crystal Cove residents, who bank on the town''s reputation to attract tourists, are prepared to do what it takes to protect their turf.', NULL, NULL, 9.8352, 8.23, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4087, 30191, 'tt0062597', NULL, 'The Outsider', 'The Outsider', 'tv', 1968, 'https://image.tmdb.org/t/p/w500/g6Z14qTpELq28RsbP3QSFy3Ecyq.jpg', 'https://image.tmdb.org/t/p/original/xV1YvbmHzrFWBFvT0KGvXBxdQGJ.jpg', 'The Outsider was the story of David Ross, a go-it-alone private investigator who''s always where the action is. Darren McGavin played Ross, a man living in an off-beat, always-dangerous world. The series aired for one season on NBC and was a precursor of sorts to The Rockford Files in that it featured a loner private detective who had previously done time in prison for a crime he didn''t commit and who never quite fit into a rapidly changing environment.', NULL, NULL, 2.1341, 6.0, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4088, 154916, 'tt15964848', NULL, 'The Makanai: Cooking for the Maiko House', '舞妓さんちのまかないさん', 'tv', 2023, 'https://image.tmdb.org/t/p/w500/ynV4fQ9GOsGsOtFfxaRkjpiAFLt.jpg', 'https://image.tmdb.org/t/p/original/cIv50iy1hTTRvjBOo6Xzs6kplQ4.jpg', 'Two inseparable friends move to Kyoto to chase their dreams of becoming maiko, but decide to pursue different passions while living under the same roof.', NULL, NULL, 1.7526, 7.589, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4089, 1304313, 'tt32612507', NULL, 'Lee Cronin''s The Mummy', 'Lee Cronin''s The Mummy', 'movie', 2026, 'https://image.tmdb.org/t/p/w500/1q308iixueCU4pFtSYugNOevtNx.jpg', 'https://image.tmdb.org/t/p/original/s3tHm62ohyb0I5vSnPrpczCBtSX.jpg', 'The young daughter of a journalist disappears into the desert without a trace—eight years later, the broken family is shocked when she is returned to them, as what should be a joyful reunion turns into a living nightmare.', NULL, NULL, 98.2575, 7.969, 0, 2.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4090, 15849, 'tt0023245', NULL, 'The Mummy', 'The Mummy', 'movie', 1932, 'https://image.tmdb.org/t/p/w500/vSKpbZVvzqQcw6htiyEinbCY9vq.jpg', 'https://image.tmdb.org/t/p/original/7LIbyeZwoeMPPfSaYuQ6VxrCi4T.jpg', 'An ancient Egyptian priest named Imhotep is revived when a British archaeological expedition finds his mummy and one of the researchers accidentally reads an ancient life-giving spell. Imhotep escapes from the field site and searches for the reincarnation of the soul of his lover.', NULL, NULL, 1.4863, 6.751, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
