INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4100, 11051, 'tt0095497', NULL, 'The Last Temptation of Christ', 'The Last Temptation of Christ', 'movie', 1988, 'https://image.tmdb.org/t/p/w500/7L4qwrC1mipZXJfU5oRgQWChLv1.jpg', 'https://image.tmdb.org/t/p/original/rBqdcQeM1h05YjF9rFtPWnNaDO2.jpg', 'Jesus, a humble Judean carpenter beginning to see that he is the son of God, is drawn into revolutionary action against the Roman occupiers by Judas -- despite his protestations that love, not violence, is the path to salvation. The burden of being the savior of mankind torments Jesus throughout his life, leading him to doubt.', NULL, NULL, 1.6466, 7.211, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
