INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4102, 140032, 'tt0166198', NULL, 'The Fountain of Youth', 'The Fountain of Youth', 'movie', 1958, 'https://image.tmdb.org/t/p/w500/lPEeC7TgWLD96UZDWIYU8BGbA9U.jpg', 'https://image.tmdb.org/t/p/original/wCXVPTQgJRoTMG8phRpaLaPnTcc.jpg', 'A darkly comic fable about vanity and desire, "The Fountain of Youth" follows a newly married couple whose relationship is destabilized by the arrival of a potion that promises centuries of youth and beauty—but in a quantity sufficient for only one person. As temptation and resentment grow, the gift becomes a catalyst for moral and emotional collapse. Written, directed, and narrated by Orson Welles and based on John Collier’s short story “Youth from Vienna,” the film uses stylized narration and experimental visual techniques to construct a compact essay on human vanity.  (Note: Originally produced in 1956 as a television pilot and broadcast once in 1958 as part of NBC’s Colgate Theatre anthology series (S1E5); it later achieved independent archival and cultural status, including a 1958 Peabody Award.)', NULL, NULL, 0.3755, 6.188, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
