INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4112, 23488, 'tt1235124', NULL, 'Dorian Gray', 'Dorian Gray', 'movie', 2009, 'https://image.tmdb.org/t/p/w500/uRKt8nYdy7EO4uqeKVVpZRmqrxF.jpg', 'https://image.tmdb.org/t/p/original/ij9ai1FDd2ErfRJ8PJrAWakzVEo.jpg', 'Seduced into the decadent world of Lord Henry Wotton, handsome young aristocrat Dorian Gray becomes obsessed with maintaining his youthful appearance, and commissions a special portrait that will weather the winds of time while he remains forever young. When Gray''s obsession spirals out of control, his desperate attempts to safeguard his secret turn his once-privileged life into a living hell.', NULL, NULL, 1.2552, 6.044, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
