INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4114, 988402, 'tt24216998', NULL, 'Humanist Vampire Seeking Consenting Suicidal Person', 'Vampire humaniste cherche suicidaire consentant', 'movie', 2023, 'https://image.tmdb.org/t/p/w500/m5OItLBY5T38ew1YI4VSIXjl5G2.jpg', 'https://image.tmdb.org/t/p/original/gbpy4mwYEodTutM9Z1HTEPK6i3S.jpg', 'Sasha is a young vampire with a serious problem: she''s too sensitive to kill. When her exasperated parents cut off her blood supply, Sasha''s life is in jeopardy. Luckily, she meets Paul, a lonely teenager with suicidal tendencies who is willing to give his life to save hers. But their friendly agreement soon becomes a nocturnal quest to fulfill Paul''s last wishes before day breaks.', NULL, NULL, 1.0962, 7.431, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4115, 1683, 'tt0444682', NULL, 'The Reaping', 'The Reaping', 'movie', 2007, 'https://image.tmdb.org/t/p/w500/o8Vl4Vxp5LBth9J6Aa3k6PAefxt.jpg', 'https://image.tmdb.org/t/p/original/4eakTJuJD3sRGfv1qVWW46iPq82.jpg', 'Katherine Morrissey, a former Christian missionary, lost her faith after the tragic deaths of her family. Now she applies her expertise to debunking religious phenomena. When a series of biblical plagues overrun a small town, Katherine arrives to prove that a supernatural force is not behind the occurrences, but soon finds that science cannot explain what is happening. Instead, she must regain her faith to combat the evil that waits in a Louisiana swamp.', NULL, NULL, 2.1612, 5.766, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
