INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4120, 38358, 'tt1320244', NULL, 'The Last Exorcism', 'The Last Exorcism', 'movie', 2010, 'https://image.tmdb.org/t/p/w500/eOo9tgGjxdsQEgqc6g7E1NL8460.jpg', 'https://image.tmdb.org/t/p/original/fyNEA2BZ5Yixu6Wub9OtIqlmJBQ.jpg', 'After years of performing “exorcisms” and taking believers’ money, Reverend Marcus travels to rural Louisiana with a film crew so he can dispel what he believes is the myth of demonic possession. The dynamic reverend is certain that this will be another routine “exorcism” on a disturbed religious fanatic but instead comes upon the blood-soaked farm of the Sweetzer family and a true evil he would have never thought imaginable.', NULL, NULL, 1.575, 5.684, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4121, 318, 'tt0111880', NULL, 'American Gothic', 'American Gothic', 'tv', 1995, 'https://image.tmdb.org/t/p/w500/qajOMTtQ958JEpmokPXTruwA9qp.jpg', 'https://image.tmdb.org/t/p/original/itisXkOIsntQacvuO5BF05xHJ60.jpg', 'Everything is not what it seems in Trinity, South Carolina. Sheriff Lucas Buck develops a sinister interest in Caleb. Caleb''s cousin Gail tries to protect him, but that''s complicated since she has feelings for Sheriff Buck. And Caleb''s dead sister, Merlyn, returns as an angel, warning him that Buck is an incarnation of evil - and may not be human.', NULL, NULL, 3.1292, 7.4, 0, 7.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4122, 595, 'tt0056592', NULL, 'To Kill a Mockingbird', 'To Kill a Mockingbird', 'movie', 1962, 'https://image.tmdb.org/t/p/w500/gZycFUMLx2110dzK3nBNai7gfpM.jpg', 'https://image.tmdb.org/t/p/original/zP6pqpSRRiOCjjC5oWKZKkHqoSB.jpg', 'Scout Finch, 6, and her older brother Jem live in sleepy Maycomb, Alabama, spending much of their time with their friend Dill and spying on their reclusive and mysterious neighbor, Boo Radley. When Atticus, their widowed father and a respected lawyer, defends a black man named Tom Robinson against fabricated rape charges, the trial and tangent events expose the children to evils of racism and stereotyping.', NULL, NULL, 3.6209, 7.99, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4123, 1632, 'tt0095647', NULL, 'Mississippi Burning', 'Mississippi Burning', 'movie', 1988, 'https://image.tmdb.org/t/p/w500/wvEx2WbxZXYljQ9vSoq37NgeXcJ.jpg', 'https://image.tmdb.org/t/p/original/sYpNbnOlIKW5nlrPDFOGpnCUlz9.jpg', 'Two FBI agents investigating the murder of civil rights workers during the 60s seek to breach the conspiracy of silence in a small Southern town where segregation divides black and white. The younger agent trained in FBI school runs up against the small town ways of his partner, a former sheriff.', NULL, NULL, 1.9059, 7.673, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4124, 949423, 'tt18925334', NULL, 'Pearl', 'Pearl', 'movie', 2022, 'https://image.tmdb.org/t/p/w500/z5uIG81pXyHKg7cUFIu84Wjn4NS.jpg', 'https://image.tmdb.org/t/p/original/8rmx3Wh6fQdSL2nzTmdFn9thcK8.jpg', 'Trapped on her family’s isolated farm, Pearl must tend to her ailing father under the bitter and overbearing watch of her devout mother. Lusting for a glamorous life like she’s seen in the movies, Pearl’s ambitions, temptations, and repressions collide.', NULL, NULL, 6.4884, 7.226, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4125, 8197, 'tt0119668', NULL, 'Midnight in the Garden of Good and Evil', 'Midnight in the Garden of Good and Evil', 'movie', 1997, 'https://image.tmdb.org/t/p/w500/cXS5o6RIp8m1epBm5I7cX49bfFd.jpg', 'https://image.tmdb.org/t/p/original/zDtIIaPdcRvZnvpD1qnI8v4nHOR.jpg', 'A visiting city reporter''s assignment suddenly revolves around the murder trial of a local millionaire, whom he befriends.', NULL, NULL, 1.3669, 6.343, 0, 6.5, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4126, 71979, 'tt6106704', NULL, 'Damnation', 'Damnation', 'tv', 2017, 'https://image.tmdb.org/t/p/w500/rmoUClMYqrQ7EWWQXvgzWcjlb1W.jpg', 'https://image.tmdb.org/t/p/original/3rmS7KF3JxrSFlFqsz1yyhxgQcL.jpg', 'Seth Davenport is masquerading as a small town Iowa preacher in the hopes of starting a full-blown insurrection against the status quo, unaware that an industrialist tycoon has hired a professional strikebreaker to stop the uprising by any means necessary. An epic saga of the secret history of the 1930’s American heartland, chronicling the mythic conflict and bloody struggle between big money and the downtrodden, God and greed, charlatans, and prophets.', NULL, NULL, 1.6065, 6.841, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4127, 64230, 'tt5016504', NULL, 'Preacher', 'Preacher', 'tv', 2016, 'https://image.tmdb.org/t/p/w500/ey1WQajA25E5sFGHSApcqSWUSEc.jpg', 'https://image.tmdb.org/t/p/original/bENaaAmX4d0zUYYrZyFCT1U0V86.jpg', 'A preacher sets out on a mission to make the almighty himself confess his sin of abandoning the world. With his best friend Cassidy, an alcoholic Irish vampire, his love Tulip, a red blooded gun towing Texan, and the power of genesis, an unholy child born from an angel and a devil, Jesse gives up everything to set the world straight with its creator.', NULL, NULL, 16.6511, 7.4, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4128, 9966, 'tt0425430', NULL, 'The Messengers', 'The Messengers', 'movie', 2007, 'https://image.tmdb.org/t/p/w500/ituR560dbnV4WAFPY0jJlEenGiW.jpg', 'https://image.tmdb.org/t/p/original/3Hxpsixno6oKhrDeMMc7RdVuvmM.jpg', 'When the Solomons trade in the craziness of big-city life for the quiet of a North Dakota farm, little do they expect the nightmare that follows. Soon after arriving, teenage Jess and her younger brother see terrifying apparitions and endure attacks from a supernatural source. Jess must warn her disbelieving family before it is too late to save them.', NULL, NULL, 1.3016, 5.744, 0, 9.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4129, 150202, 'tt1457765', NULL, 'The Haunting in Connecticut 2: Ghosts of Georgia', 'The Haunting in Connecticut 2: Ghosts of Georgia', 'movie', 2013, 'https://image.tmdb.org/t/p/w500/fBuk4jsOUjjjxCqS6rPgMKi1RB0.jpg', 'https://image.tmdb.org/t/p/original/jE1CpCE4tVLmU1dbVz5hC1mjmXC.jpg', 'A young family moves into a historic home in Georgia, only to learn they are not the house''s only inhabitants. Soon they find themselves in the presence of a secret rising from underground and threatening to bring down anyone in its path.', NULL, NULL, 1.6655, 5.81, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4130, 2091, 'tt0286493', NULL, 'The Badge', 'The Badge', 'movie', 2002, 'https://image.tmdb.org/t/p/w500/8GbBnwqYYfSMTwmTWxT9N3dzUfR.jpg', 'https://image.tmdb.org/t/p/original/4zyHOCGwTigPkiUW25va7nkUQ3c.jpg', 'A sheriff begins an investigation into the death of a local transsexual after hearing that high ranking politicians may have been involved. Although he is homophobic, his investigation causes him to be rejected by others, forcing him to seek help from the people he once despised.', NULL, NULL, 0.5659, 5.7, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4131, 1816, 'tt0088915', NULL, 'A Chorus Line', 'A Chorus Line', 'movie', 1985, 'https://image.tmdb.org/t/p/w500/bQzbO6y6gxePrEcU57Su8HJ9UdH.jpg', 'https://image.tmdb.org/t/p/original/AvPLYsn8SyDWFFBzBqmsohZ5p8x.jpg', 'A group of dancers congregate on the stage of a Broadway theatre to audition for a new musical production directed by Zach. After the initial eliminations, seventeen hopefuls remain, among them Cassie, who once had a tempestuous romantic relationship with Zach. She is desperate enough for work to humble herself and audition for him; whether he''s willing to let professionalism overcome his personal feelings about their past remains to be seen.', NULL, NULL, 1.7164, 6.228, 0, 2.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4132, 14008, 'tt0294425', NULL, 'Cadet Kelly', 'Cadet Kelly', 'movie', 2002, 'https://image.tmdb.org/t/p/w500/eKtznndgJoVG9S9UENc7kHqmhgM.jpg', 'https://image.tmdb.org/t/p/original/5BShmjcYdkuTbSIWufRzNpZFUNK.jpg', 'Hyperactive teenager Kelly is enrolled into a military school when her new stepfather becomes the Commandant. At first she has problems fitting in and taking orders until she tries out for the drill team.', NULL, NULL, 1.3918, 6.2, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4133, 9899, 'tt0395251', NULL, 'The Producers', 'The Producers', 'movie', 2005, 'https://image.tmdb.org/t/p/w500/nG0Bix2SH2SQcbAIGhb6yqTG5UH.jpg', 'https://image.tmdb.org/t/p/original/8PU4tUGUdrKujKwkUkw3M9ZrAaw.jpg', 'A conniving Broadway producer and his meek accountant plan to profit from charming wealthy old biddies to invest in an overbudget production, and then put on a sure-fire disaster, so nobody will ask for their money back — and what''s more disastrous than a tasteless musical celebrating Adolf Hitler.', NULL, NULL, 1.0565, 6.177, 0, 3.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4134, 10890, 'tt0083131', NULL, 'Stripes', 'Stripes', 'movie', 1981, 'https://image.tmdb.org/t/p/w500/vP8tPOgmJSNOh4bpOv1bFjid3rZ.jpg', 'https://image.tmdb.org/t/p/original/RtNJPHoCYXLdc0ckyBd4E3Xlkf.jpg', 'Hard-luck cabbie John Winger, directionless after being fired from his job and dumped by his girlfriend, enlists in the U.S. Army with his close pal, Russell Ziskey. After his barely satisfactory performance in basic training, the irreverent Winger emerges as the figurehead for a ragtag band of misfits. However, his hijinks threaten to cause an international scandal when he inadvertently commandeers a military assault vehicle behind enemy lines.', NULL, NULL, 1.9056, 6.565, 0, 4.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4135, 9595, 'tt0102059', NULL, 'Hot Shots!', 'Hot Shots!', 'movie', 1991, 'https://image.tmdb.org/t/p/w500/koLIB5263emHxewmwgBBK26vjeS.jpg', 'https://image.tmdb.org/t/p/original/4RriqSJFCQkYpRhxFnQGh3sxZYY.jpg', 'The gang that created Airplane! and The Naked Gun sets its sights on Top Gun in this spoof. Topper Harley is a talented but unstable fighter pilot with an axe to grind: clearing the family name. His mission is to avenge his father and save a mission sabotaged by greedy weapons manufacturers. He also gets involved in a relationship with Ramada Thompson, a woman with an unusually talented stomach. Hot Shots! makes fun of a variety of other films, from Dances with Wolves to The Fabulous Baker Boys.', NULL, NULL, 4.8003, 6.589, 0, 2.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4136, 9336, 'tt0087928', NULL, 'Police Academy', 'Police Academy', 'movie', 1984, 'https://image.tmdb.org/t/p/w500/3PriqoVUQcPwcyvk0SJRiMTdBJK.jpg', 'https://image.tmdb.org/t/p/original/6qAYgsvnH4wUS9fAcrxUvUtCM6x.jpg', 'New rules enforced by the Lady Mayoress mean that sex, weight, height and intelligence need no longer be a factor for joining the Police Force. This opens the floodgates for all and sundry to enter the Police Academy, much to the chagrin of the instructors. Not everyone is there through choice, though. Social misfit Mahoney has been forced to sign up as the only alternative to a jail sentence and it doesn''t take long before he falls foul of the boorish Lieutenant Harris. But before long, Mahoney realises that he is enjoying being a police cadet and decides he wants to stay... while Harris decides he wants Mahoney out!', NULL, NULL, 3.4492, 6.716, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
