INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4147, 14908, 'tt0119640', NULL, 'McHale''s Navy', 'McHale''s Navy', 'movie', 1997, 'https://image.tmdb.org/t/p/w500/tg9qzqF349j526pNZnjPB4p2UED.jpg', 'https://image.tmdb.org/t/p/original/uTp1WgfD43U6g4iP44VcoKQcm1H.jpg', 'Retired Lieutenant Commander Quinton McHale spends his days puttering around the Caribbean in the old PT-73 selling homebrew, ice cream, and swimsuit calendars. He''s brought out of retirement when his old nemesis turned the second best terrorist in the world, Major Vladikov, takes over the island of San Moreno and starts building a nuclear launch silo on it. With help from his old crew and hindrances from Captain Wallace B. Binghampton, who sank a cruise liner a while back, McHale tries to put Vladikov out of business.', NULL, NULL, 0.4815, 4.451, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
