INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4149, 9472, 'tt0364725', NULL, 'DodgeBall: A True Underdog Story', 'DodgeBall: A True Underdog Story', 'movie', 2004, 'https://image.tmdb.org/t/p/w500/r8KbNHkkwFXLjV1suGwm0Qjure5.jpg', 'https://image.tmdb.org/t/p/original/1nL5TJrldKI4rIj16tZTdqpdYL3.jpg', 'When megalomaniacal White Goodman, the owner of a trendy, high-end fitness center, makes a move to take over the struggling local gym run by happy-go-lucky Pete La Fleur, there''s only one way for La Fleur to fight back: dodgeball. Aided by a dodgeball guru and Goodman''s attorney, La Fleur and his rag-tag team of underdogs launch a knock-down, drag-out battle in which the winner takes all.', NULL, NULL, 2.6096, 6.365, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
