INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4152, 17287, 'tt0462485', NULL, 'Poultrygeist: Night of the Chicken Dead', 'Poultrygeist: Night of the Chicken Dead', 'movie', 2006, 'https://image.tmdb.org/t/p/w500/vSeehH4s274kdZXEMKnPE2tlqco.jpg', 'https://image.tmdb.org/t/p/original/jtnFTuRejS925CJkXf3MNCqtT8n.jpg', 'When the American Chicken Bunker, a military themed fast food restaurant, builds its latest chain restaurant on the site of an ancient Native American burial ground, the displaced spirits take revenge on unsuspecting diners and transform them into chicken zombies! Now, it’s up to a dimwitted counter boy, his collegiate lesbian ex-girlfriend and a burqa-wearing fry cook to put an end to the foul feathered menace once and for all.', NULL, NULL, 0.5645, 5.9, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
