INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4160, NULL, NULL, 36952, 'Wolfenstein II: The New Colossus', 'Wolfenstein II: The New Colossus', 'game', 2017, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21c5.jpg', NULL, 'Wolfenstein II: The New Colossus is the eleventh installment of the Wolfenstein series and a sequel to the 2014''s Wolfenstein: The New Order. The game follows the main protagonist, William Joseph "B.J." Blazkowicz, in his efforts to ignite a Second American Revolution.

The game is played from a first-person perspective and most of its levels are navigated on foot. The story is arranged in chapters, which players complete in order to progress. A binary choice in the prologue alters the game''s entire storyline; some characters and small plot points are replaced throughout the timelines. The game features a variety of weapons, most of which can be dual wielded. A cover system is also present.', 'https://www.igdb.com/games/wolfenstein-ii-the-new-colossus', '["PlayStation 4", "PC (Microsoft Windows)", "Xbox One", "Nintendo Switch"]', NULL, NULL, 0, 9.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
