INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4204, 32180, 'tt1591375', NULL, 'Pretty Wild', 'Pretty Wild', 'tv', 2010, 'https://image.tmdb.org/t/p/w500/xaFha8Fn57ziCq4CN82K26mYEdA.jpg', 'https://image.tmdb.org/t/p/original/oYNK7wA4FhW58miGVAqeDdkNAYm.jpg', 'Three beautiful, and somewhat unconventional, sisters whose family is rocked by scandal and the lure of instant fame and fortune in Hollywood. Nineteen-year-old Tess, the oldest, works as a model and is the true party girl of the family who frequents the hottest celebrity hangouts. Her younger sister, Lexi, 18, longs for the attention Tess gets — but her life is suddenly turned upside down after she is arrested as part of an alleged Hollywood burglary ring. And although she''s the youngest at 15, Gabby tends to act the most mature and is often seen as the family''s moral compass. Their eccentric mom Andrea (a former wild child turned self-help enthusiast) is now realizing the consequences of letting her daughters enjoy too much freedom growing up. After years of letting her girls run wild, is it too little too late?', NULL, NULL, 0.4493, 3.5, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4205, 10468, 'tt0191754', NULL, '28 Days', '28 Days', 'movie', 2000, 'https://image.tmdb.org/t/p/w500/tlgz7Shx0UavR5pyITeJ2mUHKFI.jpg', 'https://image.tmdb.org/t/p/original/gXahs8xwiF2VMZJK7JgtSZSgTDt.jpg', 'After getting into a car accident while drunk on the day of her sister''s wedding, Gwen Cummings is given a choice between prison or a rehab center. She chooses rehab, but is extremely resistant to taking part in any of the treatment programs they have to offer, refusing to admit that she has an alcohol addiction.', NULL, NULL, 1.2618, 6.156, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
