INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4224, 9838, 'tt0089421', NULL, 'King Solomon''s Mines', 'King Solomon''s Mines', 'movie', 1985, 'https://image.tmdb.org/t/p/w500/kpaW2gh0hjMPwoz30JL3gRKi2Ho.jpg', 'https://image.tmdb.org/t/p/original/aVgqxRQ8M8aJnfO1eUZEmNJSTxm.jpg', 'Ever in search of adventure, explorer Allan Quatermain agrees to join the beautiful Jesse Huston on a mission to locate her archaeologist father, who has been abducted for his knowledge of the legendary mines of King Solomon. As the kidnappers, led by sinister German military officer Bockner, journey into the wilds of Africa, Allan and Jesse track the party and must contend with fierce natives and dangerous creatures, among other perils.', NULL, NULL, 2.0924, 5.433, 0, 11.5, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
