INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4227, 9326, 'tt0088011', NULL, 'Romancing the Stone', 'Romancing the Stone', 'movie', 1984, 'https://image.tmdb.org/t/p/w500/qfIlVOYZH5RiZ0ndFKUpr5Zn2Bx.jpg', 'https://image.tmdb.org/t/p/original/8v5X238laJCSGN5Oq6BHEQEOWL5.jpg', 'Though she can spin wild tales of passionate romance, novelist Joan Wilder has no life of her own. Then one day adventure comes her way in the form of a mysterious package. It turns out that the parcel is the ransom she''ll need to free her abducted sister, so Joan flies to South America to hand it over. But she gets on the wrong bus and winds up hopelessly stranded in the jungle.', NULL, NULL, 2.6074, 6.772, 0, 11.5, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4228, 10303, 'tt0089370', NULL, 'The Jewel of the Nile', 'The Jewel of the Nile', 'movie', 1985, 'https://image.tmdb.org/t/p/w500/6VjsIhnIcrz2XdQVHdsMj5DdSa1.jpg', 'https://image.tmdb.org/t/p/original/6QstEy47t8yLY3FZCqukbKlYIH3.jpg', 'Joan Wilder is thrust back into a world of murder, chases, foreign intrigue... and love. This time out she''s duped by a duplicitous Arab dignitary who brings her to the Middle East, ostensibly to write a book about his life. Of course, he''s up to no good, and Joan is just another pawn in his wicked game. But Jack Colton and his sidekick Ralph show up to help our intrepid heroine save the day.', NULL, NULL, 2.0066, 6.213, 0, 11.5, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4229, 2023, 'tt0317648', NULL, 'Hidalgo', 'Hidalgo', 'movie', 2004, 'https://image.tmdb.org/t/p/w500/iGzENlBPYJEFWZnye4t3nqWSSp1.jpg', 'https://image.tmdb.org/t/p/original/sAiTihJ8bjEqg8nYUIlTQUnVXuj.jpg', 'Set in 1890, this is the story of a Pony Express courier who travels to Arabia to compete with his horse, Hidalgo, in a dangerous race for a massive contest prize, in an adventure that sends the pair around the world...', NULL, NULL, 1.9213, 6.917, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4230, 10586, 'tt0116409', NULL, 'The Ghost and the Darkness', 'The Ghost and the Darkness', 'movie', 1996, 'https://image.tmdb.org/t/p/w500/3KEPs6RKlin9pT9fqjtW7MSLC8H.jpg', 'https://image.tmdb.org/t/p/original/kM2RkLCt3ElQ2NfHgw1CzZXRGfZ.jpg', 'Sir Robert Beaumont is behind schedule on a railroad in Africa. Enlisting noted engineer John Henry Patterson to right the ship, Beaumont expects results. Everything seems great until the crew discovers the mutilated corpse of the project''s foreman, seemingly killed by a lion. After several more attacks, Patterson calls in famed hunter Charles Remington, who has finally met his match in the bloodthirsty lions.', NULL, NULL, 2.6565, 6.827, 0, 13.5, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4231, 40790, 'tt0047464', NULL, 'Secret of the Incas', 'Secret of the Incas', 'movie', 1954, 'https://image.tmdb.org/t/p/w500/f09jwcHubGvpEN5Lnt7tl1FKgye.jpg', 'https://image.tmdb.org/t/p/original/oXrCYrSk6KmJRVjkjXnaYpBqcuf.jpg', 'Harry Steele (Charlton Heston) is a tourist guide determined to make his fortune by finding the Sunburst, an Inca treasure.', NULL, NULL, 0.7698, 5.864, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4232, 2177, 'tt0071005', NULL, 'Land of the Lost', 'Land of the Lost', 'tv', 1974, 'https://image.tmdb.org/t/p/w500/4AvO1tZUsoupwSQ0Aetr93JJJIf.jpg', 'https://image.tmdb.org/t/p/original/kJB50LyeILumAAhSJetPtpiHLmD.jpg', 'Rick Marshall and his children Will and Holly are on a weekend expedition rafting down a river when an enormous earthquake diverts them to an eclectic alien world inhabited by dinosaurs, chimpanzee-like cavemen called Pakuni, and aggressive, humanoid lizard creatures called Sleestak.', NULL, NULL, 1.4328, 7.176, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4233, 3003, 'tt0302739', NULL, 'The Lost World', 'The Lost World', 'movie', 2001, 'https://image.tmdb.org/t/p/w500/22PtJeHtI19j15nkQiM561Ng7cH.jpg', 'https://image.tmdb.org/t/p/original/kENpaFN3dKuAcsESuwXRwGrSRZk.jpg', 'This Lost World is a splendid BBC TV dramatisation of Sir Arthur Conan Doyle''s famous adventure story. Bob Hoskins makes an unusually genial Professor Challenger, far less of a bully than Doyle''s character, but his slightly stereotyped companions are nicely filled out by a solid cast. James Fox is Challenger''s more timid but still covertly adventurous rival, Tom Ward is the moustachioed big game hunter who faces an Allosaurus with an elephant gun, and Matthew Rhys plays the tagalong reporter hoping to impress his faithless fiancée.', NULL, NULL, 1.1464, 6.128, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4234, 38006, 'tt0050095', NULL, 'The Abominable Snowman', 'The Abominable Snowman', 'movie', 1957, 'https://image.tmdb.org/t/p/w500/j0mz19eFHrloyAbLmxXEYqfJ2k.jpg', 'https://image.tmdb.org/t/p/original/pETrI33C25cdF0cIEcAXFYEbh2u.jpg', 'A kindly English botanist and a gruff American promoter lead an expedition to the Himalayas in search of the legendary Yeti.', NULL, NULL, 0.6947, 6.213, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4235, 17578, 'tt0983193', NULL, 'The Adventures of Tintin', 'The Adventures of Tintin', 'movie', 2011, 'https://image.tmdb.org/t/p/w500/fQZ3sLR1Fi63NMsNRbjm9q5qODJ.jpg', 'https://image.tmdb.org/t/p/original/6mqgl2szMLRYj4lhlXOjju5Tpeo.jpg', 'Intrepid young reporter, Tintin, and his loyal dog, Snowy, are thrust into a world of high adventure when they discover a ship carrying an explosive secret. As Tintin is drawn into a centuries-old mystery, Ivan Ivanovitch Sakharine suspects him of stealing a priceless treasure. Tintin and Snowy, with the help of salty, cantankerous Captain Haddock and bumbling detectives, Thompson and Thomson, travel half the world, one step ahead of their enemies, as Tintin endeavors to find the Unicorn, a sunken ship that may hold a vast fortune, but also an ancient curse.', NULL, NULL, 4.5114, 6.927, 0, 11.5, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4236, 24575, 'tt0081400', NULL, 'Raise the Titanic', 'Raise the Titanic', 'movie', 1980, 'https://image.tmdb.org/t/p/w500/XvukyvRCbkYKKv1TdtlyNxvzEl.jpg', 'https://image.tmdb.org/t/p/original/k0mwvvXFvBAVTrlYf5D2sETXMHX.jpg', 'To obtain a supply of a rare mineral, a ship raising operation is conducted for the only known source, the Titanic.', NULL, NULL, 0.5439, 5.362, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4237, 336808, 'tt4285496', NULL, 'Embrace of the Serpent', 'El abrazo de la serpiente', 'movie', 2015, 'https://image.tmdb.org/t/p/w500/t3Lmw8jvm7tpik0lSkub8hU4oRW.jpg', 'https://image.tmdb.org/t/p/original/zhXmJnPIoncBQ2TY8IEWc4s9vbh.jpg', 'The epic story of the first contact, encounter, approach, betrayal and, eventually, life-transcending friendship, between Karamakate, an Amazonian shaman, last survivor of his people, and two scientists that, over the course of 40 years, travel through the Amazon in search of a sacred plant that can heal them. Inspired by the journals of the first explorers of the Colombian Amazon, Theodor Koch-Grunberg and Richard Evans Schultes.', NULL, NULL, 1.1827, 7.69, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4238, 9588, 'tt0102744', NULL, 'Quigley Down Under', 'Quigley Down Under', 'movie', 1990, 'https://image.tmdb.org/t/p/w500/sRgeovNyj1pARroKclXzJhOwPbW.jpg', 'https://image.tmdb.org/t/p/original/wro8QfQhL9GoQJgG8WK9pC7wGyX.jpg', 'American Matt Quigley answers Australian land baron Elliott Marston''s ad for a sharpshooter to kill the dingoes on his property. But when Quigley finds out that Marston''s real target is the aborigines, Quigley hits the road. Now, even American expatriate Crazy Cora can''t keep Quigley safe in his cat-and-mouse game with the homicidal Marston.', NULL, NULL, 2.0, 6.721, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
