INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4283, 226790, 'tt0904056', NULL, 'Open Your Mind', 'めざめの方舟', 'movie', 2005, 'https://image.tmdb.org/t/p/w500/bYf4pTExRiFSt7K9fUMADJEFsEn.jpg', NULL, 'The plot of Open Your Mind follows the extraterrestrial origin of life, coming from outerspace as six deities (Intermission act), evolving into water (Sho-ho) then emerging to the air (Hyakkin) and to the ground (Ku-nu). Each one of these creatures rules one of the six elements of the godai philosophy, i.e. Earth, Water, Fire, Wind (referred to as kaze in the Hyakkin chant), Sky and Consciousness (referred to as "Awakening" in the movie''s title).', NULL, NULL, 0.7308, 5.8, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
