INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4285, 219619, 'tt0371962', NULL, 'Strange Attractor', 'Strange Attractor', 'movie', 2003, 'https://image.tmdb.org/t/p/w500/ektyWDQPXeIWBjn9ckKI6ZDHt6E.jpg', NULL, 'A strange attractor is created when lovers synchronize their minds, bodies, and computers using botanical substances. An enchanted and skewed digital dream world, Strange Attractor inverts the Adam and Eve story and re-visions the Persian/Arabian tale of Layla and Majnun. Sufi love madness meets media prophecy.', NULL, NULL, 0.6044, 7.8, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4286, 18162, 'tt0457400', NULL, 'Land of the Lost', 'Land of the Lost', 'movie', 2009, 'https://image.tmdb.org/t/p/w500/hVCJzmK9l5FD01LFYAB1zcmmw7s.jpg', 'https://image.tmdb.org/t/p/original/6FTIgtJk1mqmBTg9AEBrRKhLG1c.jpg', 'On his latest expedition, has-been scientist Dr. Rick Marshall is sucked into a space-time vortex alongside his crack-smart research assistant Holly and redneck survivalist Will into a world populated by marauding dinosaurs and painfully slow creatures called Sleestaks. With no weapons, few skills and questionable smarts, the trio must rely on their only ally, a primate named Chaka, to try to survive long enough to figure out a way back home.', NULL, NULL, 3.0265, 5.458, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
