INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4293, 271, 'tt0088015', NULL, 'Ronia: The Robber''s Daughter', 'Ronja Rövardotter', 'movie', 1984, 'https://image.tmdb.org/t/p/w500/gatMa1qfwpJqiawPjJxodUvdB0.jpg', 'https://image.tmdb.org/t/p/original/lPYts3qpBDMlJaGjzd7nA5Piyd2.jpg', 'Ronia lives happily in her father''s castle until she comes across a new playmate, Birk, in the nearby dark forest. The two explore the wilderness, braving dangerous Witchbirds and Rump-Gnomes. But when their families find out Birk and Ronia have been playing together, they forbid them to see each other again. Indeed, their fathers are competing robber chieftains and bitter enemies. Now the two spunky children must try to tear down the barriers that have kept their families apart for so long.', NULL, NULL, 1.1951, 7.03, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4294, 94653, 'tt0120393', NULL, 'Twilight of the Ice Nymphs', 'Twilight of the Ice Nymphs', 'movie', 1997, 'https://image.tmdb.org/t/p/w500/qNAhdQe3JQDoCu18vlZBJeTdutm.jpg', 'https://image.tmdb.org/t/p/original/xk6EO8Y69C2a88gUhkeOsLXMig8.jpg', 'Set in a blazing land where the sun ceaselessly shines, this dramatic fantasy examines love’s darker aspects.', NULL, NULL, 0.4424, 5.886, 0, 11.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4295, 3200, 'tt0206511', NULL, 'Even Stevens', 'Even Stevens', 'tv', 2000, 'https://image.tmdb.org/t/p/w500/6wdftSHL6EF8sevUFJSVOnEBOHT.jpg', 'https://image.tmdb.org/t/p/original/unpuZD1N1Wfxo9izU1YX88qKvv6.jpg', 'The Stevens are a middle-class family living in Sacramento, CA. Husband and father Steve is a successful attorney. Wife and mother Eileen is a state Senator. Their oldest child Donnie ia a high-school sports legend. Ren, an 8th-grader, is just about the perfect daughter. She makes the best grades, she''s popular, she does volunteer work and other extracurricular tasks by the score. Her brother Louis, in the 7th grade, is her opposite. He likes to sleep late, he''s messy, his grades are not good, he''s frequently in detention and he seems to take nothing seriously. But he is serious about finding something of his own that he can do to put himself on a par with the rest of his overachieving family. Though he and Ren occasionally soften their attitudes toward each other, at any given moment the''re likely to be fighting like mongoose and cobra.', NULL, NULL, 7.3207, 7.034, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4296, 11259, 'tt0104231', NULL, 'Far and Away', 'Far and Away', 'movie', 1992, 'https://image.tmdb.org/t/p/w500/is80o8p0sCok3UqtnHEE2oyXyad.jpg', 'https://image.tmdb.org/t/p/original/1Qf6lzJFhNiRVQrS2N05PQbInmY.jpg', 'A young free-spirited Irish woman from an affluent Protestant family spontaneously befriends a street-smart commoner cheated by her family’s hostile land takeovers. They escape to America, ready to take advantage of the 19th century Oklahoma land rush.', NULL, NULL, 1.5639, 6.777, 0, 10.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
