INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4302, 35692, 'tt0046786', NULL, 'The Black Knight', 'The Black Knight', 'movie', 1954, 'https://image.tmdb.org/t/p/w500/bMVzUJTHapgymAgzJgGNd3q6Bs9.jpg', 'https://image.tmdb.org/t/p/original/ufcP29FyVUd2GGkAY2rllkauzRU.jpg', 'John, a blacksmith and swordsmith, is tutored at Camelot. As a commoner, he can''t hope to win the hand of Lady Linet, daughter of the Earl of Yeoniland, so he creates a secret alternate identity as the Black Knight. In this new role, he is now able to help King Arthur when Saracens and Cornish men—disguised as Vikings -- plot to take over the country.', NULL, NULL, 0.4577, 6.409, 0, 2.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4303, 34637, 'tt0095709', NULL, 'The Navigator: A Medieval Odyssey', 'The Navigator: A Medieval Odyssey', 'movie', 1988, 'https://image.tmdb.org/t/p/w500/3jgWf292UUNZyaaLppFlYWFpDOE.jpg', 'https://image.tmdb.org/t/p/original/a5kImJOOgKOiCNHvYwTJPnJMzQr.jpg', 'Cumberland, 1348. The plague is spreading in medieval England. The remote village of little Griffin is also threatened. But the 9-year-old boy has a recurring dream that holds the key to a tiny hope of survival: a lake with a coffin floating on it. A white church with an iron cross. A falling glove. A falling silhouette. A torch tumble through a dark shaft into infinity. With his brother he recognizes in it a prophecy to escape the Black Death. So they embark with a few men on a journey to a distant cathedral, where they want to set up an iron cross as an offering to God. Her path leads them through a deep and dark mine shaft into an unknown land and completely outlandish time - into the present-day New Zealand of the 1980s.', NULL, NULL, 0.3182, 6.165, 0, 1.0, '2026-07-20 04:02:06', '2026-07-20 04:02:06');
