UPDATE "recommendations" SET "tmdb_id"=179111, "imdb_id"='tt2375574', "igdb_id"=NULL, "title"='A Field in England', "original_title"='A Field in England', "media_type"='movie', "release_year"=2013, "poster_url"='https://image.tmdb.org/t/p/w500/dKhMJr8yoHVyvxyUiAeIn2hKVdL.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/euBvKWkvYD38O7dMMvw3GvrkZoa.jpg', "overview"='During the Civil War in 17th-Century England, a small group of deserters flee from a raging battle through an overgrown field. They are captured by an alchemist, who forces the group to aid him in his search to find a hidden treasure that he believes is buried in the field. Crossing a vast mushroom circle, which provides their first meal, the group quickly descend into a chaos of arguments, fighting and paranoia, and, as it becomes clear that the treasure might be something other than gold, they slowly become victim to the terrifying energies trapped inside the field.', "external_url"=NULL, "platforms"=NULL, "popularity"=1.1118, "vote_average"=6.212, "is_ambiguous"=0, "evidence_score"=9.67, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 04:02:06' WHERE "id"=21;
