UPDATE "recommendations" SET "tmdb_id"=274854, "imdb_id"='tt1618442', "igdb_id"=NULL, "title"='The Last Witch Hunter', "original_title"='The Last Witch Hunter', "media_type"='movie', "release_year"=2015, "poster_url"='https://image.tmdb.org/t/p/w500/dS9YdnJkxtKE2PKCSsxTaO7Jpf5.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/mXmvN6drkdU1PWFF92AGklEVIa3.jpg', "overview"='The modern world holds many secrets, but by far the most astounding is that witches still live among us; vicious supernatural creatures intent on unleashing the Black Death upon the world and putting an end to the human race once and for all. Armies of witch hunters have battled this unnatural enemy for centuries, including Kaulder, a valiant warrior who many years ago slayed the all-powerful Witch Queen, decimating her followers in the process. In the moments right before her death, the Queen cursed Kaulder with immortality, forever separating him from his beloved wife and daughter. Today, Kaulder is the last living hunter who has spent his immortal life tracking down rogue witches, all the while yearning for his long-lost family.', "external_url"=NULL, "platforms"=NULL, "popularity"=5.1292, "vote_average"=6.016, "is_ambiguous"=0, "evidence_score"=2.36421428571428577e+01, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 04:02:06' WHERE "id"=39;
