UPDATE "recommendations" SET "tmdb_id"=89, "imdb_id"='tt0097576', "igdb_id"=NULL, "title"='Indiana Jones and the Last Crusade', "original_title"='Indiana Jones and the Last Crusade', "media_type"='movie', "release_year"=1989, "poster_url"='https://image.tmdb.org/t/p/w500/sizg1AU8f8JDZX4QIgE4pjUMBvx.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/12fvZHskx57kQfNEUXJ3v0flWYQ.jpg', "overview"='In 1938, an art collector appeals to eminent archaeologist Dr. Indiana Jones to embark on a search for the Holy Grail. Indy learns that a medieval historian has vanished while searching for it, and the missing man is his own father, Dr. Henry Jones Sr.. He sets out to rescue his father by following clues in the old man''s notebook, which his father had mailed to him before he went missing. Indy arrives in Venice, where he enlists the help of a beautiful academic, Dr. Elsa Schneider, along with Marcus Brody and Sallah. Together they must stop the Nazis from recovering the power of eternal life and taking over the world!', "external_url"=NULL, "platforms"=NULL, "popularity"=8.6456, "vote_average"=7.853, "is_ambiguous"=0, "evidence_score"=6.755, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 04:02:06' WHERE "id"=87;
