UPDATE "recommendations" SET "tmdb_id"=49730, "imdb_id"='tt1486185', "igdb_id"=NULL, "title"='Red Riding Hood', "original_title"='Red Riding Hood', "media_type"='movie', "release_year"=2011, "poster_url"='https://image.tmdb.org/t/p/w500/ixQYkLeLlTTnAoT32dukndyObB6.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/r4A5SQSGTfleodMm45w7MJgE2WF.jpg', "overview"='Valerie is in love with a brooding outsider, Peter, but her parents have arranged for her to marry another man. Unwilling to lose each other, Valerie and Peter plan to run away together when Valerie''s older sister is killed by a werewolf that prowls the dark forest surrounding their village. Panic grips the town as Valerie discovers that she has a unique connection to the beast--one that inexorably draws them together, making her both suspect ... and bait.', "external_url"=NULL, "platforms"=NULL, "popularity"=4.3, "vote_average"=5.976, "is_ambiguous"=0, "evidence_score"=9.34, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 04:02:06' WHERE "id"=561;
