UPDATE "recommendations" SET "tmdb_id"=11866, "imdb_id"='tt0377062', "igdb_id"=NULL, "title"='Flight of the Phoenix', "original_title"='Flight of the Phoenix', "media_type"='movie', "release_year"=2004, "poster_url"='https://image.tmdb.org/t/p/w500/pj3nKoouBhLkO94XUg8y5IeZ32c.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/mWXU29QjfjEG37d0c2hE11MWRGq.jpg', "overview"='When an oil rig in the Gobi Desert of Mongolia proves unproductive, an aircraft crew are sent to shut the operation down and fly them out. On the flight out over the desert on the way to Beijing, Capt. Frank Towns and co-pilot A.J. are unable to keep their cargo plane, a C-119 Flying Boxcar, in the air when a violent sandstorm strikes. Crash-landing in a remote uncharted part of the desert, the two pilots and their passengers -- a crew of oil workers and a drifter -- must work together to survive by rebuilding the aircraft. Soon, low supplies and a band of merciless smugglers add even greater urgency to their task.', "external_url"=NULL, "platforms"=NULL, "popularity"=2.0509, "vote_average"=6.001, "is_ambiguous"=0, "evidence_score"=8.673333333333332e+00, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 04:02:06' WHERE "id"=863;
