UPDATE "recommendations" SET "tmdb_id"=7090, "imdb_id"='tt0209077', "igdb_id"=NULL, "title"='Ken Park', "original_title"='Ken Park', "media_type"='movie', "release_year"=2003, "poster_url"='https://image.tmdb.org/t/p/w500/p6ElNTWEbibYlobVeiIDHBvL1kF.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/uw5uCdiF0HSCyXml0GsUe95ejuw.jpg', "overview"='Teen skater Ken Park (nicknamed Krap Nek; his name spelled and pronounced backward) kills himself at a Visalia skate park; his death bookends the lives of four other young people who knew him: Shawn, the most conventional; Tate brims with psychotic rage; Claude is habitually harassed by his brutish father and coddled, rather uncomfortably, by his enormously pregnant mother; and Peaches looks after her devoutly religious father, but yearns for freedom. They''re all rather tight, or so they claim.', "external_url"=NULL, "platforms"=NULL, "popularity"=2.2563, "vote_average"=5.991, "is_ambiguous"=0, "evidence_score"=9.0066666666666677e+00, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 04:02:06' WHERE "id"=1036;
