UPDATE "recommendations" SET "tmdb_id"=453, "imdb_id"='tt0268978', "igdb_id"=NULL, "title"='A Beautiful Mind', "original_title"='A Beautiful Mind', "media_type"='movie', "release_year"=2001, "poster_url"='https://image.tmdb.org/t/p/w500/rEIg5yJdNOt9fmX4P8gU9LeNoTQ.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/hCJFWTPghXCwwSpvPpAoIB8318Q.jpg', "overview"='From the heights of notoriety to the depths of depravity, John Forbes Nash Jr. experiences it all. As a brilliant but socially awkward mathematician, he made a groundbreaking discovery early in his career and stands on the brink of international acclaim. But as the handsome and arrogant Nash accepts secret work in cryptography, he becomes entangled in a mysterious conspiracy. His life takes a nightmarish turn and he soon finds himself on a painful and harrowing journey of self-discovery.', "external_url"=NULL, "platforms"=NULL, "popularity"=4.8147, "vote_average"=7.854, "is_ambiguous"=0, "evidence_score"=9.43333333333333357e+00, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 04:02:06' WHERE "id"=2383;
