UPDATE "recommendations" SET "tmdb_id"=1562, "imdb_id"='tt0463854', "igdb_id"=NULL, "title"='28 Weeks Later', "original_title"='28 Weeks Later', "media_type"='movie', "release_year"=2007, "poster_url"='https://image.tmdb.org/t/p/w500/oix0aNv1lvW3nUGspUyvSIBlpbs.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/83ownpZPvBHJD5UVNShzQfa3LaW.jpg', "overview"='Twenty-eight weeks after the spread of a deadly rage virus, the inhabitants of the British Isles have lost their battle against the onslaught, as the virus has killed everyone there. Six months later, a group of Americans dare to set foot on the Isles, convinced the danger has passed. But it soon becomes all too clear that the scourge continues to live, waiting to pounce on its next victims.', "external_url"=NULL, "platforms"=NULL, "popularity"=3.9708, "vote_average"=6.602, "is_ambiguous"=0, "evidence_score"=2.0, "created_at"='2026-07-20 01:02:04', "updated_at"='2026-07-20 04:02:06' WHERE "id"=2908;
UPDATE "recommendations" SET "tmdb_id"=588228, "imdb_id"='tt9777666', "igdb_id"=NULL, "title"='The Tomorrow War', "original_title"='The Tomorrow War', "media_type"='movie', "release_year"=2021, "poster_url"='https://image.tmdb.org/t/p/w500/34nDCQZwaEvsy4CFO5hkGRFDCVU.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/yizL4cEKsVvl17Wc1mGEIrQtM2F.jpg', "overview"='The world is stunned when a group of time travelers arrive from the year 2051 to deliver an urgent message: Thirty years in the future, mankind is losing a global war against a deadly alien species. The only hope for survival is for soldiers and civilians from the present to be transported to the future and join the fight. Among those recruited is high school teacher and family man Dan Forester. Determined to save the world for his young daughter, Dan teams up with a brilliant scientist and his estranged father in a desperate quest to rewrite the fate of the planet.', "external_url"=NULL, "platforms"=NULL, "popularity"=14.0125, "vote_average"=7.516, "is_ambiguous"=0, "evidence_score"=2.0, "created_at"='2026-07-20 01:02:04', "updated_at"='2026-07-20 04:02:06' WHERE "id"=2925;
