UPDATE "recommendations" SET "tmdb_id"=NULL, "imdb_id"=NULL, "igdb_id"=185258, "title"='ARC Raiders', "original_title"='ARC Raiders', "media_type"='game', "release_year"=2025, "poster_url"='https://images.igdb.com/igdb/image/upload/t_cover_big/co9rk1.jpg', "backdrop_url"=NULL, "overview"='ARC Raiders is a multiplayer extraction adventure, set in a lethal future earth, ravaged by a mysterious mechanized threat known as ARC. Enlist as a Raider and scavenge the surface to thrive in a desolate world. But beware of the machines. Beware of Raiders preying on others.

ARC Raiders blends the tension from extraction shooters with atmospheric settings from the adventure genre. Lurking threats—from deadly machines to other Raiders—create a constant ebb and flow of intensity, where every moment is charged with the thrill of high stakes. Extract valuable loot and explore the unfolding mysteries of a vibrant, lethal world.

ARC Raiders supports seamless social play across PlayStation, Xbox, and PC. Play with your squad and thrive as a team, or rise in the ranks as a lone ranger.', "external_url"='https://www.igdb.com/games/arc-raiders', "platforms"='["Xbox Series X|S", "PC (Microsoft Windows)", "PlayStation 5"]', "popularity"=NULL, "vote_average"=NULL, "is_ambiguous"=0, "evidence_score"=7.0, "created_at"='2026-07-20 01:02:04', "updated_at"='2026-07-20 04:02:06' WHERE "id"=2984;
