UPDATE "recommendations" SET "tmdb_id"=1687999, "imdb_id"=NULL, "igdb_id"=NULL, "title"='TWICE IN A BLUE MOON (After Nokomis)', "original_title"='TWICE IN A BLUE MOON (After Nokomis)', "media_type"='movie', "release_year"=2021, "poster_url"=NULL, "backdrop_url"=NULL, "overview"='Twelve full moons were filmed consecutively each month for a year starting on the full Blue Moon of October 2020 and finishing on the full moon of 21 September 2021. Very fortunately I recorded 2 Blue Moons over the 12 months. The second part of the title refers to "Nokomis" meaning "Grandmother" to the Native North American language of the Ojibwe or Ainishinaabe people and made famous by the Longfellow''s poem "The Song of Hiawatha". The full moon names are those given them by the Native North Americans.', "external_url"=NULL, "platforms"=NULL, "popularity"=0.1251, "vote_average"=0.0, "is_ambiguous"=0, "evidence_score"=2.0, "created_at"='2026-07-20 01:02:04', "updated_at"='2026-07-20 04:02:06' WHERE "id"=3362;
